module cascaded_encoder #(parameter N = 8) (
    input_signal [N-1:0] input_signal,
    output reg [M-1:0] out,
    output reg [M-2:0] out_upper_half,
    output reg [M-2:0] out_lower_half
);

    // Calculate the width of the output based on the input width
    integer M = N > 1 ? ceil(N/2) : 0;

    // Instantiate two priority encoders for the upper and lower halves
    priority_encoder #(N, M) encoder_upper (.input_signal(input_signal[N/2-1:0]), .out(out_upper_half));
    priority_encoder #(N, M) encoder_lower (.input_signal(input_signal[N/2:0]), .out(out_lower_half));

    // Determine which half has the active input
    always @(input_signal) begin
        if (out_upper_half[M-1]) begin
            out = out_upper_half;
        end else if (out_lower_half[M-1]) begin
            out = out_lower_half;
        end else begin
            out = 3'b0; // Default case when no inputs are active
        end
    end

endmodule

output.rtl/Attenuator.sv:
always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk_div2 <= 1'b0;
        current_state <= IDLE;
        ATTN_CLK      <= 1'b0;
        ATTN_DATA     <= 1'b0;
        ATTN_LE       <= 1'b0;
        shift_reg     <= 5'b00000;
        bit_count     <= 3'd0;
        old_data      <= 5'b00000;
    end else begin
        case (current_state)
            IDLE: begin
                if (data != old_data) begin
                    shift_reg <= data;
                    next_state <= LOAD;
                end else begin
                    ATTN_CLK <= 1'b0;
                    ATTN_DATA <= 1'b0;
                    ATTN_LE <= 1'b0;
                    current_state <= IDLE;
                end
            end
            LOAD: begin
                bit_count <= 3'd5;
                next_state <= SHIFT;
            end
            SHIFT: begin
                if (bit_count == 3'd5) begin
                    ATTN_DATA <= shift_reg[bit_count - 1];
                    bit_count <= 3'd0;
                    next_state <= LATCH;
                end else begin
                    ATTN_CLK <= ~ATTN_CLK;
                    next_state <= SHIFT;
                end
            end
            LATCH: begin
                ATTN_LE <= 1'b1;
                next_state <= IDLE;
            end
        endcase
    end
end

