always_ff @(posedge w_clk, posedge w_rst) begin
  if (w_rst) begin
    w_count_bin <= 0;
    w_ptr       <= 0;
  end else begin
    if (!w_full && push) begin
      mem[w_ptr] <= w_data;
      w_ptr <= w_ptr + 1;
      w_count_bin <= w_count_bin + 1;
      w_full <= w_count_bin == DEPTH;
    end
  end
end

always_ff @(posedge r_clk, posedge r_rst) begin
  if (r_rst) begin
    r_count_bin <= 0;
    r_ptr       <= 0;
  end else begin
    if (!r_empty && pop) begin
      r_data <= mem[r_ptr];
      r_ptr <= r_ptr - 1;
      r_count_bin <= r_count_bin + 1;
      r_empty <= r_count_bin == wq2_rptr;
    end
  end
end

always_ff @(posedge r_clk or posedge r_rst) begin
  if (r_rst) begin
    r_empty <= 1;
  end else begin
    wq2_rptr <= r_count_bin;
    rq2_wptr <= wq2_rptr;
    wq2_rptr <= {wq2_rptr[0], ~wq2_rptr[1]};
    rq2_wptr <= {rq2_wptr[0], ~rq2_wptr[1]};
  end
end

input.rtl/async_filo.sv:
`timescale 1ns / 1ps

module async_filo #(
    parameter DATA_WIDTH = 16,
    parameter DEPTH      = 8
) (
    input                         w_clk,    // Write clock
    input                         w_rst,    // Write reset
    input                         push,     // Push signal
    input                         r_rst,    // Read reset
    input                         r_clk,    // Read clock
    input                         pop,      // Pop signal
    input        [DATA_WIDTH-1:0] w_data,   // Data input for push
    output logic [DATA_WIDTH-1:0] r_data,   // Data output for pop
    output logic                  r_empty,  // Empty flag
    output logic                  w_full    // Full flag
);

  // Address width
  localparam ADDR_WIDTH = $clog2(DEPTH);

  // Address pointers
  logic [ADDR_WIDTH:0] w_ptr;
  logic [ADDR_WIDTH:0] r_ptr;
  logic [ADDR_WIDTH:0] w_ptr_next;
  logic [ADDR_WIDTH:0] r_ptr_next;

  logic [DATA_WIDTH-1:0] mem[0:DEPTH-1];
  wire [ADDR_WIDTH-1:0] w_addr;
  wire [ADDR_WIDTH-1:0] r_addr;


  logic w_full_d1;

  logic [ADDR_WIDTH:0] w_ptr_b1;

  logic r_ptr_1;
  always @(posedge w_clk) begin
    w_ptr <= r_ptr_1;
  end

  always @(posedge w_clk) begin
    w_ptr <= w_ptr + 1;
  end

  always @(*) begin
    if (push) w_full_d1 = 1;
  end

  logic [ADDR_WIDTH+1:0] w_full_f1;
  always @(posedge w_clk) begin
    w_full_f1 <= w_count_next_bin;
  end

  always @(posedge w_rst) begin
    w_ptr_b1 <= w_count_bin;
  end

  always @(posedge w_clk) begin
    if (push && !w_full) w_addr = w_addr + 1;
  end

  always @(posedge w_clk) begin
    if (push && !w_full) mem[w_addr] <= w_data;
  end

  assign r_data = mem[r_addr];

  logic [ADDR_WIDTH:0] wq1_rptr, wq2_rptr;
  logic [ADDR_WIDTH:0] rq1_wptr, rq2_wptr;

  always @(posedge w_clk, posedge w_rst) begin
    if (w_rst) begin
      wq1_rptr <= 0;
      wq2_rptr <= 0;
    end else begin
      wq1_rptr <= r_ptr;
      wq2_rptr <= wq1_rptr;
    end
  end

  always @(posedge r_clk, posedge r_rst) begin
    if (r_rst) begin
      rq1_wptr <= 0;
      rq2_wptr <= 0;
    end else begin
      rq1_wptr <= w_ptr;
      rq2_wptr <= rq1_wptr;
    end
  end

  always @(posedge w_clk) begin
    if (push && !w_full) w_addr = w_addr + 1;
  end

  function automatic [ADDR_WIDTH:0] bin2gray(input [ADDR_WIDTH:0] bin);
    bin2gray = bin ^ (bin >> 1);
  endfunction

  function automatic [ADDR_WIDTH:0] gray2bin(input [ADDR_WIDTH:0] gray);
    gray2bin = gray;
    for (int i = 1; i <= ADDR_WIDTH; i++) gray2bin[i] = gray2bin[i] ^ gray2bin[i-1];
  endfunction

  logic [ADDR_WIDTH:0] w_count_bin, r_count_bin;
  wire [ADDR_WIDTH:0] w_count_next_bin, r_count_next_bin;
  wire [ADDR_WIDTH:0] wq2_rptr_bin;

  always @(posedge w_clk, posedge w_rst) begin
    if (w_rst) begin
      w_count_bin <= 0;
      w_ptr       <= 0;
    end else begin
      w_count_bin <= w_count_next_bin;
      w_ptr       <= w_ptr_next;
    end
  end

  assign w_count_next_bin = w_count_bin + ({(ADDR_WIDTH+1){push}} & ~{(ADDR_WIDTH+1){w_full}});
  assign w_ptr_next = bin2gray(w_count_next_bin);
  assign wq2_rptr_bin = gray2bin(wq2_rptr);

  always @(posedge r_clk, posedge r_rst) begin
    if (r_rst) begin
      r_count_bin <= 0;
      r_ptr       <= 0;
    end else begin
      r_count_bin <= r_count_next_bin;
      r_ptr       <= r_ptr_next;
    end
  end

  assign r_count_next_bin = r_count_bin + ({(ADDR_WIDTH+1){pop}} & ~{(ADDR_WIDTH+1){r_empty}});
  assign r_ptr_next = bin2gray(r_count_next_bin);

  assign w_addr = w_count_bin[ADDR_WIDTH-1:0];
  assign r_addr = r_count_bin[ADDR_WIDTH-1:0];

  always @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      r_empty <= 1;
    end else begin
      r_empty <= (r_ptr_next == rq2_wptr);
    end
  end

  always @(posedge w_clk) begin
    case (w_ptr)
      5'b00000: w_full_d1 <= 1;
      5'b11111: w_full_d1 <= 0;
      default:  w_full_d1 <= 2;
    endcase
  end
  always @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      w_full <= 0;
    end else begin
      w_full <= (w_count_next_bin[ADDR_WIDTH] != wq2_rptr_bin[ADDR_WIDTH]) && 
                  (w_count_next_bin[ADDR_WIDTH-1:0] == wq2_rptr_bin[ADDR_WIDTH-1:0]);
    end
  end

endmodule

output.rtl/async_filo.sv:
module async_filo #(
    parameter DATA_WIDTH = 16,
    parameter DEPTH      = 8
) (
    input                         w_clk,    // Write clock
    input                         w_rst,    // Write reset
    input                         push,     // Push signal
    input                         r_rst,    // Read reset
    input                         r_clk,    // Read clock
    input                         pop,      // Pop signal
    input                        [DATA_WIDTH-1:0] w_data,   // Data input for push
    output logic [DATA_WIDTH-1:0] r_data,   // Data output for pop
    output logic                  r_empty,  // Empty flag
    output logic                  w_full    // Full flag
);

  // Address width
  localparam ADDR_WIDTH = $clog2(DEPTH);

  // Address pointers
  logic [ADDR_WIDTH:0] w_ptr, r_ptr;
  logic [ADDR_WIDTH:0] w_ptr_next, r_ptr_next;
  logic [DATA_WIDTH-1:0] mem[0:DEPTH-1];
  wire [ADDR_WIDTH-1:0] w_addr, r_addr;

  logic w_full;

  // Reset handling
  always @(posedge w_rst) begin
    w_ptr <= 0;
    r_ptr <= 0;
    w_full <= 0;
  end

  // Gray code conversion
  function automatic [ADDR_WIDTH:0] bin2gray(input [ADDR_WIDTH:0] bin);
    bin2gray = bin ^ (bin >> 1);
  endfunction

  function automatic [ADDR_WIDTH:0] gray2bin(input [ADDR_WIDTH:0] gray);
    gray2bin = gray;
    for (int i = 1; i <= ADDR_WIDTH; i++) gray2bin[i] = gray2bin[i] ^ gray2bin[i-1];
  endfunction

  // Write pointers
  always @(posedge w_clk) begin
    if (push && !w_full) begin
      w_addr <= w_addr + 1;
      mem[w_addr] <= w_data;
    end
  end

  // Read pointers
  always @(posedge r_clk) begin
    if (r_rst) begin
      r_ptr <= 0;
    end else begin
      r_ptr <= r_ptr_next;
    end
  end

  // Count pointers
  logic [ADDR_WIDTH:0] w_count_bin, r_count_bin;
  logic w_count_next_bin, r_count_next_bin;

  always @(posedge w_clk) begin
    if (w_rst) begin
      w_count_bin <= 0;
      w_ptr       <= 0;
      w_full      <= 0;
    end else begin
      w_count_bin <= w_count_next_bin;
      w_ptr       <= w_ptr_next;
      w_full      <= (w_count_next_bin[ADDR_WIDTH] != wq2_rptr_bin[ADDR_WIDTH]) && 
                      (w_count_next_bin[ADDR_WIDTH-1:0] == wq2_rptr_bin[ADDR_WIDTH-1:0]);
    end
  end

  always @(posedge r_clk) begin
    if (r_rst) begin
      r_count_bin <= 0;
      r_ptr       <= 0;
      r_empty     <= 1;
    end else begin
      r_count_bin <= r_count_next_bin;
      r_ptr       <= r_ptr_next;
      r_empty     <= (r_ptr_next == rq2_wptr);
    end
  end

endmodule

input.rtl/axi_alu.sv:
module axi_alu (
    input  wire        axi_clk_in,
    input  wire        fast_clk_in,
    input  wire        reset_in,

    // AXI Interface
    input  wire        axi_awvalid_i,
    input  wire        axi_wvalid_i,
    input  wire        axi_bready_i,
    input  wire        axi_arvalid_i,
    input  wire        axi_rready_i,

    output wire        axi_awready_o,
    output wire        axi_wready_o,
    output wire        axi_bvalid_o,
    output wire        axi_arready_o,
    output wire        axi_rvalid_o,

    input  wire [31:0] axi_awaddr_i,
    input  wire [31:0] axi_wdata_i,
    input  wire [31:0] axi_araddr_i,

    input  wire [3:0]  axi_wstrb_i,
    output wire [31:0] axi_rdata_o,
    output wire [63:0] result_o
);

    wire        clk;
    wire [31:0] operand_a, operand_b, operand_c;
    wire [1:0]  op_select;
    wire        start, clock_control;
    wire [31:0] data_a;
    wire [31:0] data_b;
    wire [31:0] data_c;

    wire [31:0] operand_a_cdc, operand_b_cdc, operand_c_cdc;
    wire [1:0]  op_select_cdc;
    wire        start_cdc;
    wire [31:0] operand_a_sync, operand_b_sync, operand_c_sync;
    wire [1:0]  op_select_sync;
    wire        start_sync;

    clock_control u_clock_control (
        .axi_clk_in  (axi_clk_in),
        .fast_clk_in (fast_clk_in),
        .clk_ctrl    (clock_control),
        .clk         (clk)
    );

    axi_csr_block u_axi_csr_block (
        .axi_aclk_i    (axi_clk_in),
        .axi_areset_i  (reset_in),
        .axi_awvalid_i   (axi_awvalid_i),
        .axi_awready_o   (axi_awready_o),
        .axi_awaddr_i    (axi_awaddr_i),
        .axi_wvalid_i    (axi_wvalid_i),
        .axi_wready_o    (axi_wready_o),
        .axi_wdata_i     (axi_wdata_i),
        .axi_wstrb_i     (axi_wstrb_i),
        .axi_bvalid_o    (axi_bvalid_o),
        .axi_bready_i    (axi_bready_i),
        .axi_arvalid_i   (axi_arvalid_i),
        .axi_arready_o   (axi_arready_o),
        .axi_araddr_i    (axi_araddr_i),
        .axi_rvalid_o    (axi_rvalid_o),
        .axi_rready_i    (axi_rready_i),
        .axi_rdata_o     (axi_rdata_o),
        .operand_a     (operand_a_cdc),
        .operand_b     (operand_b_cdc),
        .operand_c     (operand_c_cdc),
        .op_select     (op_select_cdc),
        .start         (start_cdc),
        .clock_control (clock_control)
    );

    // CDC logic is only active when clock_control is HIGH
    assign operand_a = (clock_control) ? operand_a_sync : operand_a_cdc;
    assign operand_b = (clock_control) ? operand_b_sync : operand_b_cdc;
    assign operand_c = (clock_control) ? operand_c_sync : operand_c_cdc;
    assign op_select = (clock_control) ? op_select_sync : op_select_cdc;
    assign start     = (clock_control) ? start_sync : start_cdc;

    // CDC Synchronizers (only used when fast_clk is selected)
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_a (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_a_cdc), .data_out(operand_a_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_b (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_b_cdc), .data_out(operand_b_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_c (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_c_cdc), .data_out(operand_c_sync));
    cdc_synchronizer #(.WIDTH(2))  u_cdc_op_select  (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(op_select_cdc), .data_out(op_select_sync));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_start      (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(start_cdc), .data_out(start_sync));

    memory_block u_memory_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .address_a  (operand_a[5:0]),
        .address_b  (operand_b[5:0]),
        .address_c  (operand_c[5:0]),
        .data_a     (data_a),
        .data_b     (data_b),
        .data_c     (data_c)
    );

    dsp_block u_dsp_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .operand_a  (data_a),
        .operand_b  (data_b),
        .operand_c  (data_c),
        .op_select  (op_select),
        .start      (start),
        .result     (result_o)
    );

endmodule

// ------------------------------------------------------------------
// CDC Synchronizer Module (Double Flop Synchronization)
// ------------------------------------------------------------------
module cdc_synchronizer #(parameter WIDTH = 1) (
    input wire clk_src,  // Source clock
    input wire clk_dst,  // Destination clock
    input wire reset_in, // Reset signal
    input wire [WIDTH-1:0] data_in,  // Data from source domain
    output reg [WIDTH-1:0] data_out  // Synchronized data in destination domain
);
    reg [WIDTH-1:0] data_sync_1, data_sync_2;

    always @(posedge clk_dst or posedge reset_in) begin
        if (reset_in) begin
            data_sync_1 <= {WIDTH{1'b0}};
            data_sync_2 <= {WIDTH{1'b0}};
            data_out    <= {WIDTH{1'b0}};
        end else begin
            data_sync_1 <= data_in;   // First stage
            data_sync_2 <= data_sync_1; // Second stage
            data_out    <= data_sync_2; // Stable output
        end
    end
endmodule

// ------------------------------------------------------------------
// Clock Control Module
// ------------------------------------------------------------------
module clock_control (
    input  wire axi_clk_in,
    input  wire fast_clk_in,
    input  wire clk_ctrl,
    output wire clk
);
    assign clk = clk_ctrl ? fast_clk_in : axi_clk_in;
endmodule

// ------------------------------------------------------------------
// AXI-to-CSR Register Block (With Write Response Handling)
// ------------------------------------------------------------------
module axi_csr_block (
    input  wire        axi_aclk_i,
    input  wire        axi_areset_i,

    // AXI Write Address Channel
    input  wire        axi_awvalid_i,
    output reg         axi_awready_o,
    input  wire [31:0] axi_awaddr_i,

    // AXI Write Data Channel
    input  wire        axi_wvalid_i,
    output reg         axi_wready_o,
    input  wire [31:0] axi_wdata_i,
    input  wire [3:0]  axi_wstrb_i,

    // AXI Write Response Channel (FIXED)
    output reg         axi_bvalid_o,
    input  wire        axi_bready_i,

    // AXI Read Address Channel
    input  wire        axi_arvalid_i,
    output reg         axi_arready_o,
    input  wire [31:0] axi_araddr_i,

    // AXI Read Data Channel
    output reg         axi_rvalid_o,
    input  wire        axi_rready_i,
    output reg  [31:0] axi_rdata_o,

    // CSR Outputs
    output reg  [31:0] operand_a,
    output reg  [31:0] operand_b,
    output reg  [31:0] operand_c,
    output reg  [1:0]  op_select,
    output reg         start,
    output reg         clock_control
);
    reg [31:0] csr_reg [0:4];

    always @(posedge axi_aclk_i or posedge axi_areset_i) begin
        if (axi_areset_i) begin
            operand_a     <= 32'd0;
            operand_b     <= 32'd0;
            operand_c     <= 32'd0;
            op_select     <= 2'd0;
            start         <= 1'b0;
            clock_control <= 1'b0;
            axi_awready_o <= 0;
            axi_wready_o  <= 0;
            axi_bvalid_o  <= 0; // Set response valid
            axi_arready_o <= 0;
            axi_rvalid_o  <= 0;
            axi_rdata_o   <= 32'd0;
            csr_reg[0]    <= 32'd0;
            csr_reg[1]    <= 32'd0;
            csr_reg[2]    <= 32'd0;
            csr_reg[3]    <= 32'd0;
            csr_reg[4]    <= 32'd0;
        end else begin
            // Handle AXI Write
            if (axi_awvalid_i && axi_wvalid_i) begin
                csr_reg[axi_awaddr_i[4:2]] <= axi_wdata_i;
                axi_awready_o <= 1;
                axi_wready_o  <= 1;
                axi_bvalid_o  <= 1; // Set response valid
            end else begin
                axi_awready_o <= 0;
                axi_wready_o  <= 0;
                axi_bvalid_o  <= 0; // Set response valid
            end

            // Handle Write Response
            if (axi_bvalid_o && axi_bready_i) begin
                axi_bvalid_o <= 0; // Clear response once acknowledged
            end

            // Handle AXI Read
            if (axi_arvalid_i) begin
                axi_arready_o <= 1;
                axi_rvalid_o  <= 1;
                axi_rdata_o    <= csr_reg[axi_araddr_i[4:2]];
            end else begin
                axi_arready_o <= 0;
                axi_rvalid_o  <= 0;
            end

            // Update CSR Registers
            operand_a     <= csr_reg[0];
            operand_b     <= csr_reg[1];
            operand_c     <= csr_reg[2];
            op_select     <= csr_reg[3][1:0];
            start         <= csr_reg[3][2];
            clock_control <= csr_reg[4][0];
        end
    end
endmodule

// ------------------------------------------------------------------
// Memory Block (ROM)
// ------------------------------------------------------------------
module memory_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [5:0]  address_a,
    input  wire [5:0]  address_b,
    input  wire [5:0]  address_c,
    output wire [31:0] data_a,
    output wire [31:0] data_b,
    output wire [31:0] data_c
);
    reg [31:0] rom [0:63];

    initial begin
        $readmemh("../rom_data.mem", rom);
    end

    assign data_a = (reset_in) ? 32'd0 : rom[address_a];
    assign data_b = (reset_in) ? 32'd0 : rom[address_b];
    assign data_c = (reset_in) ? 32'd0 : rom[address_c];
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
// ------------------------------------------------------------------
module dsp_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [31:0] operand_a,
    input  wire [31:0] operand_b,
    input  wire [31:0] operand_c,
    input  wire [1:0]  op_select,
    input  wire        start,
    output reg  [63:0] result
);
    always @(posedge clk or posedge reset_in) begin
        if (reset_in)
            result <= 64'd0;
        else begin
            if (start) begin
                case (op_select)
                    2'b00: result <= (operand_a + operand_b) * operand_c;    // MAC
                    2'b01: result <= operand_a * operand_b;    // Multiplication
                    2'b10: result <= operand_a >> operand_b[4:0]; // Shift Right
                    2'b11: result <= operand_b ? operand_a / operand_b : 64'hDEADDEAD; // Division (handle divide by zero)
                endcase
            end
        end
    end
endmodule

output.rtl/axi_alu.sv:
module axi_alu (
    input  wire        axi_clk_in,
    input  wire        fast_clk_in,
    input  wire        reset_in,

    // AXI Interface
    input  wire        axi_awvalid_i,
    input  wire        axi_wvalid_i,
    input  wire        axi_bready_i,
    input  wire        axi_arvalid_i,
    input  wire        axi_rready_i,

    output wire        axi_awready_o,
    output wire        axi_wready_o,
    output wire        axi_bvalid_o,
    output wire        axi_arready_o,
    output wire        axi_rvalid_o,

    input  wire [31:0] axi_awaddr_i,
    input  wire [31:0] axi_wdata_i,
    input  wire [31:0] axi_araddr_i,

    input  wire [3:0]  axi_wstrb_i,
    output wire [31:0] axi_rdata_o,
    output wire [63:0] result_o
);

    wire        clk;
    wire [31:0] operand_a, operand_b, operand_c;
    wire [1:0]  op_select;
    wire        start, clock_control;
    wire [31:0] data_a;
    wire [31:0] data_b;
    wire [31:0] data_c;

    wire [31:0] operand_a_cdc, operand_b_cdc, operand_c_cdc;
    wire [1:0]  op_select_cdc;
    wire        start_cdc;
    wire [31:0] operand_a_sync, operand_b_sync, operand_c_sync;
    wire [1:0]  op_select_sync;
    wire        start_sync;

    clock_control u_clock_control (
        .axi_clk_in  (axi_clk_in),
        .fast_clk_in (fast_clk_in),
        .clk_ctrl    (clock_control),
        .clk         (clk)
    );

    axi_csr_block u_axi_csr_block (
        .axi_aclk_i    (axi_clk_in),
        .axi_areset_i  (reset_in),
        .axi_awvalid_i   (axi_awvalid_i),
        .axi_awready_o   (axi_awready_o),
        .axi_awaddr_i    (axi_awaddr_i),
        .axi_wvalid_i    (axi_wvalid_i),
        .axi_wready_o    (axi_wready_o),
        .axi_wdata_i     (axi_wdata_i),
        .axi_wstrb_i     (axi_wstrb_i),
        .axi_bvalid_o    (axi_bvalid_o),
        .axi_bready_i    (axi_bready_i),
        .axi_arvalid_i   (axi_arvalid_i),
        .axi_arready_o   (axi_arready_o),
        .axi_araddr_i    (axi_araddr_i),
        .axi_rvalid_o    (axi_rvalid_o),
        .axi_rready_i    (axi_rready_i),
        .axi_rdata_o     (axi_rdata_o),
        .operand_a     (operand_a_cdc),
        .operand_b     (operand_b_cdc),
        .operand_c     (operand_c_cdc),
        .op_select     (op_select_cdc),
        .start         (start_cdc),
        .clock_control (clock_control)
    );

    // CDC logic is only active when clock_control is HIGH
    assign operand_a = (clock_control) ? operand_a_sync : operand_a_cdc;
    assign operand_b = (clock_control) ? operand_b_sync : operand_b_cdc;
    assign operand_c = (clock_control) ? operand_c_sync : operand_c_cdc;
    assign op_select = (clock_control) ? op_select_sync : op_select_cdc;
    assign start     = (clock_control) ? start_sync : start_cdc;

    // CDC Synchronizers (only used when fast_clk is selected)
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_a (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_a_cdc), .data_out(operand_a_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_b (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_b_cdc), .data_out(operand_b_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_c (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_c_cdc), .data_out(operand_c_sync));
    cdc_synchronizer #(.WIDTH(2))  u_cdc_op_select  (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(op_select_cdc), .data_out(op_select_sync));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_start      (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(start_cdc), .data_out(start_sync));

    memory_block u_memory_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .address_a  (operand_a[5:0]),
        .address_b  (operand_b[5:0]),
        .address_c  (operand_c[5:0]),
        .data_a     (data_a),
        .data_b     (data_b),
        .data_c     (data_c)
    );

    dsp_block u_dsp_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .operand_a  (data_a),
        .operand_b  (data_b),
        .operand_c  (data_c),
        .op_select  (op_select),
        .start      (start),
        .result     (result_o)
    );

endmodule

// ------------------------------------------------------------------
// CDC Synchronizer Module (Double Flop Synchronization)
// ------------------------------------------------------------------
module cdc_synchronizer #(parameter WIDTH = 1) (
    input wire clk_src,  // Source clock
    input wire clk_dst,  // Destination clock
    input wire reset_in, // Reset signal
    input wire [WIDTH-1:0] data_in,  // Data from source domain
    output reg [WIDTH-1:0] data_out  // Synchronized data in destination domain
);
    reg [WIDTH-1:0] data_sync_1, data_sync_2;

    always @(posedge clk_dst or posedge reset_in) begin
        if (reset_in) begin
            data_sync_1 <= {WIDTH{1'b0}};
            data_sync_2 <= {WIDTH{1'b0}};
            data_out    <= {WIDTH{1'b0}};
        end else begin
            data_sync_1 <= data_in;   // First stage
            data_sync_2 <= data_sync_1; // Second stage
            data_out    <= data_sync_2; // Stable output
        end
    end
endmodule

// ------------------------------------------------------------------
// Clock Control Module
// ------------------------------------------------------------------
module clock_control (
    input  wire axi_clk_in,
    input  wire fast_clk_in,
    input  wire clk_ctrl,
    output wire clk
);
    assign clk = clk_ctrl ? fast_clk_in : axi_clk_in;
endmodule

// ------------------------------------------------------------------
// AXI-to-CSR Register Block (With Write Response Handling)
// ------------------------------------------------------------------
module axi_csr_block (
    input  wire        axi_aclk_i,
    input  wire        axi_areset_i,

    // AXI Write Address Channel
    input  wire        axi_awvalid_i,
    output reg         axi_awready_o,
    input  wire [31:0] axi_awaddr_i,

    // AXI Write Data Channel
    input  wire        axi_wvalid_i,
    output reg         axi_wready_o,
    input  wire [31:0] axi_wdata_i,
    input  wire [3:0]  axi_wstrb_i,

    // AXI Write Response Channel (FIXED)
    output reg         axi_bvalid_o,
    input  wire        axi_bready_i,

    // AXI Read Address Channel
    input  wire        axi_arvalid_i,
    output reg         axi_arready_o,
    input  wire [31:0] axi_araddr_i,

    // AXI Read Data Channel
    output reg         axi_rvalid_o,
    input  wire        axi_rready_i,
    output reg  [31:0] axi_rdata_o,

    // CSR Outputs
    output reg  [31:0] operand_a,
    output reg  [31:0] operand_b,
    output reg  [31:0] operand_c,
    output reg  [1:0]  op_select,
    output reg         start,
    output reg         clock_control
);
    reg [31:0] csr_reg [0:4];

    always @(posedge axi_aclk_i or posedge axi_areset_i) begin
        if (axi_areset_i) begin
            operand_a     <= 32'd0;
            operand_b     <= 32'd0;
            operand_c     <= 32'd0;
            op_select     <= 2'd0;
            start         <= 1'b0;
            clock_control <= 1'b0;
            axi_awready_o <= 0;
            axi_wready_o  <= 0;
            axi_bvalid_o  <= 0; // Set response valid
            axi_arready_o <= 0;
            axi_rvalid_o  <= 0;
            axi_rdata_o   <= 32'd0;
            csr_reg[0]    <= 32'd0;
            csr_reg[1]    <= 32'd0;
            csr_reg[2]    <= 32'd0;
            csr_reg[3]    <= 32'd0;
            csr_reg[4]    <= 32'd0;
        end else begin
            // Handle AXI Write
            if (axi_awvalid_i && axi_wvalid_i) begin
                csr_reg[axi_awaddr_i[4:2]] <= axi_wdata_i;
                axi_awready_o <= 1;
                axi_wready_o  <= 1;
                axi_bvalid_o  <= 1; // Set response valid
            end else begin
                axi_awready_o <= 0;
                axi_wready_o  <= 0;
                axi_bvalid_o  <= 0; // Set response valid
            end

            // Handle Write Response
            if (axi_bvalid_o && axi_bready_i) begin
                axi_bvalid_o <= 0; // Clear response once acknowledged
            end

            // Handle AXI Read
            if (axi_arvalid_i) begin
                axi_arready_o <= 1;
                axi_rvalid_o  <= 1;
                axi_rdata_o    <= csr_reg[axi_araddr_i[4:2]];
            end else begin
                axi_arready_o <= 0;
                axi_rvalid_o  <= 0;
            end

            // Update CSR Registers
            operand_a     <= csr_reg[0];
            operand_b     <= csr_reg[1];
            operand_c     <= csr_reg[2];
            op_select     <= csr_reg[3][1:0];
            start         <= csr_reg[3][2];
            clock_control <= csr_reg[4][0];
        end
    end
endmodule

// ------------------------------------------------------------------
// Memory Block (ROM)
// ------------------------------------------------------------------
module memory_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [5:0]  address_a,
    input  wire [5:0]  address_b,
    input  wire [5:0]  address_c,
    output wire [31:0] data_a,
    output wire [31:0] data_b,
    output wire [31:0] data_c
);
    reg [31:0] rom [0:63];

    initial begin
        $readmemh("../rom_data.mem", rom);
    end

    assign data_a = (reset_in) ? 32'd0 : rom[address_a];
    assign data_b = (reset_in) ? 32'd0 : rom[address_b];
    assign data_c = (reset_in) ? 32'd0 : rom[address_c];
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
// ------------------------------------------------------------------
module dsp_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [31:0] operand_a,
    input  wire [31:0] operand_b,
    input  wire [31:0] operand_c,
    input  wire [1:0]  op_select,
    input  wire        start,
    output reg  [63:0] result
);
    always @(posedge clk or posedge reset_in) begin
        if (reset_in)
            result <= 64'd0;
        else begin
            if (start) begin
                case (op_select)
                    2'b00: result <= (operand_a + operand_b) * operand_c;    // MAC
                    2'b01: result <= operand_a * operand_b;    // Multiplication
                    2'b10: result <= operand_a >> operand_b[4:0]; // Shift Right
                    2'b11: result <= operand_b ? operand_a / operand_b : 64'hDEADDEAD; // Division (handle divide by zero)
                endcase
            end
        end
    end
endmodule

output.rtl/axi_register.sv:
module axi_register #(parameter ADDR_WIDTH = 32, DATA_WIDTH = 32)
(
    input clk_i,
    input rst_n_i,
    input [ADDR_WIDTH-1:0] awaddr_i,
    input awvalid_i,
    input [DATA_WIDTH-1:0] wdata_i,
    input wvalid_i,
    input [DATA_WIDTH-1:0] wstrb_i,
    input bready_i,
    input [ADDR_WIDTH-1:0] araddr_i,
    input arvalid_i,
    output reg rready_o,
    output reg [ADDR_WIDTH-1:0] rdata_o,
    output reg rvalid_o,
    output [2:0] rresp_o,
    output reg [19:0] beat_o,
    output reg start_o,
    output reg writeback_o
);

    reg [ADDR_WIDTH-1:0] addr_reg [0:255];
    reg [20:0] beat_reg;
    reg [DATA_WIDTH-1:0] data_reg [0:255];
    reg done_reg;
    reg id_reg [0:31];

    // Initialization on reset
    always @(posedge clk_i or posedge rst_n_i) begin
        if (rst_n_i) begin
            rready_o = 0;
            rdata_o = {ADDR_WIDTH{1'b0}};
            rvalid_o = 0;
            rresp_o = 2'b00;
            beat_o = 0;
            start_o = 0;
            writeback_o = 0;
            addr_reg = {ADDR_WIDTH{0}};
            beat_reg = 0;
            data_reg = {ADDR_WIDTH{0}};
            done_reg = 0;
            id_reg = {32{1'b0}};
        end else begin
            rready_o = 1;
            id_reg = {32{1'b0}};
        end
    end

    // Address decoding
    always @(posedge clk_i) begin
        if (arvalid_i) begin
            addr_reg = araddr_i;
        end
    end

    // Write operation
    always @(posedge clk_i) begin
        if (awvalid_i) begin
            if (wvalid_i) begin
                if (wstrb_i) begin
                    if (addr_reg[0] == awaddr_i) begin
                        if (wdata_i[0]) begin
                            if (wdata_i == {DATA_WIDTH{1'b1}}) begin
                                beat_reg = wdata_i;
                                start_o = 1;
                                writeback_o = 1;
                                bready_i = 1;
                            end
                        end
                    end
                end
            end
        end
    end

    // Read operation
    always @(posedge clk_i) begin
        if (arvalid_i) begin
            if (addr_reg[0] == araddr_i) begin
                rdata_o = data_reg[addr_reg[0]];
                rvalid_o = 1;
                rresp_o = 2'b00;
            end else begin
                rdata_o = {ADDR_WIDTH{1'b0}};
                rvalid_o = 0;
                rresp_o = 2'b10;
            end
        end
    end

    // Write response
    always @(posedge clk_i) begin
        if (awvalid_i && wvalid_i && bready_i) begin
            if (addr_reg[0] == awaddr_i) begin
                if (wdata_i == {DATA_WIDTH{1'b1}}) begin
                    beat_reg = wdata_i;
                    done_reg = 0;
                    writeback_o = 0;
                end
            end
            bready_i = 0;
            bvalid_o = 1;
        end
    end

    // Done status update
    always @(posedge clk_i) begin
        if (done_i) begin
            done_reg = 1;
            rready_o = 0;
        end
    end

    // Reset functionality
    always @(posedge clk_i or posedge rst_n_i) begin
        if (rst_n_i) begin
            beat_o = 0;
            start_o = 0;
            writeback_o = 0;
            addr_reg = {ADDR_WIDTH{0}};
            data_reg = {ADDR_WIDTH{0}};
            done_reg = 0;
            id_reg = {32{1'b0}};
        end else begin
            rready_o = 1;
            id_reg = {32{1'b0}};
        end
    end

endmodule

output.rtl/axis_resize.sv:
module axis_resize (

  input                                           clk,          //Global clock signal: Signals are sampled on the rising edge of clk
  input                                           resetn,       //The global reset signal: resetn is synchronous active-LOW reset.

  input                                           s_valid,      //The s_axis_valid signal indicates that the slave is driving a valid transfer.
  output  reg                                     s_ready,      //The s_axis_ready indicates that the slave can accept a transfer in the current cycle.
  input       [15:0]  s_data,                                   //The s_axis_data is the primary payload data from slave.

  output  reg                                     m_valid,      //The m_axis_valid indicates that the master is driving a valid transfer.
  input                                           m_ready,      //The m_axis_ready indicates that the slave can accept a transfer in the current cycle.
  output  reg [7:0] m_data                                      //The m_axis_data is the primary payload data to master.
);

  reg [7:0] m_data_reg;

  always @(posedge clk) begin
    if (!resetn) begin
      s_ready <= 0;
      m_valid <= 0;
      m_data_reg <= 8'b0000_0000;
    end else begin
      if (s_valid) begin
        if (m_ready) begin
          m_data_reg <= s_data[7:0];
          s_ready <= 1;
          m_valid <= 1;
        end else begin
          m_data_reg <= 8'b0000_0000;
          s_ready <= 0;
          m_valid <= 0;
        end
      end
    end
  end

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale (
    input clk,
    input resetn,
    input dfmt_enable,
    input dfmt_type,
    input dfmt_se,
    input s_axis_valid,
    input [23:0] s_axis_data,
    output reg m_axis_ready,
    output reg m_axis_valid,
    output [31:0] m_axis_data
);

    reg [31:0] temp_data;

    always @(posedge clk or posedge resetn) begin
        if (resetn) begin
            m_axis_ready <= 0;
            m_axis_valid <= 0;
            m_axis_data <= 32'b0;
        end else begin
            if (dfmt_enable) begin
                case (dfmt_type)
                    1: temp_data = ~s_axis_data[23] ? s_axis_data : 0;
                    0: temp_data = s_axis_data[23];
                endcase

                case (dfmt_se)
                    1: temp_data = s_axis_data << 23;
                    0: temp_data = s_axis_data << 23;
                endcase

                temp_data = {temp_data, s_axis_data};
            end

            m_axis_ready <= s_axis_valid;
            m_axis_valid <= 1;
            m_axis_data <= temp_data;
        end
    end

endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input           outport_peripheral0_rready_o,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i
);

`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

// Address matching and routing logic
always @ (posedge clk_i or negedge rst_i)
begin
    if (rst_i) begin
        // Clear pending transactions and interface selections
        read_pending_q <= 4'b0;
        write_pending_q <= 4'b0;
        read_port_q    <= `ADDR_SEL_W'b0;
        write_port_q    <= `ADDR_SEL_W'b0;
    end else begin
        // Match incoming address against the Peripheral0 mask
        if (inport_araddr_i && inport_awaddr_i) begin
            if (inport_araddr_i & PERIPH0_MASK == PERIPH0_ADDR) begin
                // Incoming address matches Peripheral0, route to Peripheral0
                write_port_q    <= `ADDR_SEL_W'd1;
                read_port_q     <= `ADDR_SEL_W'd1;
                read_accept_w   <= 1'b1;
                write_accept_w  <= 1'b1;
            end else begin
                // Incoming address does not match Peripheral0, route to Default Interface
                write_port_q    <= `ADDR_SEL_W'b0;
                read_port_q     <= `ADDR_SEL_W'b0;
                read_accept_w   <= 1'b0;
                write_accept_w  <= 1'b0;
            end
        end
    end
end

// Handshake logic for Peripheral0 interface
always @ (posedge clk_i or negedge rst_i)
begin
    if (rst_i) begin
        // Reset handshake signals for Peripheral0
        outport_peripheral0_awready_i <= 1'b0;
        outport_peripheral0_wready_i <= 1'b0;
        outport_peripheral0_rready_i <= 1'b0;
        outport_peripheral0_arready_i <= 1'b0;
        outport_peripheral0_bready_i <= 1'b0;
    end else begin
        // Update handshake signals based on interface selection
        if (write_port_q == 1'd1) begin
            outport_peripheral0_awready_i <= inport_awready_o & awvalid_q & write_accept_w;
            outport_peripheral0_wready_i <= inport_wready_o & wvalid_q & write_accept_w & (write_port_r == 1'd1);
            outport_peripheral0_rready_i <= inport_rready_o & read_valid_r;
        end else begin
            outport_peripheral0_awready_i <= 1'b0;
            outport_peripheral0_wready_i <= 1'b0;
            outport_peripheral0_rready_i <= 1'b0;
            outport_peripheral0_bready_i <= 1'b0;
        end
    end
end

// Handshake logic for Default Interface
// (Similar to Peripheral0 interface, omitted for brevity)

// Write channel logic for Default Interface
// (Similar to Peripheral0 interface, omitted for brevity)

// Read channel logic for Default Interface
// (Similar to Peripheral0 interface, omitted for brevity)

