    always @(state) begin
        case (state)
            ST_ROW_FIRST: begin
                m_axis_tdata <= BORDER_COLOR;
                m_axis_tvalid <= 1;
            end
            ST_PROCESS_ROW: begin
                m_axis_tdata <= s_axis_tdata;
                m_axis_tvalid <= s_axis_tvalid;
            end
            ST_BORDER_ROW: begin
                m_axis_tdata <= BORDER_COLOR;
                m_axis_tvalid <= 1;
            end
            ST_ROW_LAST: begin
                m_axis_tdata <= BORDER_COLOR;
                m_axis_tvalid <= 1;
                m_axis_tuser <= 1;
            end
        endcase
