output.rtl/pseudo_lru_nmru_policy.sv:
module pseudo_lru_nmru_policy #(
    NWAYS = 4,
    NINDEXES = 32
) (
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output reg [$clog2(NWAYS)-1:0] way_replace
);

reg [NWAYS-1:0] recency [NINDEXES-1:0];

integer reset_counter;
always_ff @ (posedge clock or posedge reset) begin
    if (reset) begin
        for (reset_counter = 0; reset_counter < NINDEXES; reset_counter = reset_counter + 1) begin
            recency[reset_counter] <= {NWAYS{1'b0}};
        end
    end else begin
        if (access) begin
            // Set recency bit to 1 for the accessed way
            recency[index] <= {way_select{1'b1}, NWAYS{1'b0}};

            // Determine way to replace based on recency
            integer zero_count;
            integer zero_index;
            zero_count = 0;
            zero_index = -1;
            for (integer i = 0; i < NWAYS; i = i + 1) begin
                if (recency[index][i] == 0) begin
                    if (zero_count == 0) begin
                        // LRU policy: Set the lowest index with zero recency
                        zero_index = i;
                        zero_count = 1;
                    end else if (zero_count == 1) begin
                        zero_index = i;
                    end
                end
            end

            if (zero_count == 1) begin
                // LRU policy: Select the way with zero recency
                way_replace <= {zero_index{1'b1}, NWAYS{1'b0}};
            end else if (zero_count > 1) begin
                // NMRU policy: Select any way with zero recency
                way_replace <= way_select; // Any zero recency bit can be selected
            end
        end
    end
end

endmodule : pseudo_lru_nmru_policy

output.rtl/lru_counter_policy.sv:
module lru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    // Local wires for tracking LRU slot
    wire lru_slot_found;
    wire [$clog2(NWAYS)-1:0] lru_slot;

    integer i, n;

    // Recency update logic on cache hit
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin
            // Cache hit scenario
            if (access) begin
                // Set the accessed way to the most recently used
                recency[index][way_select * $clog2(NWAYS) +: $clog2(NWAYS)] <= NWAYS - 1;

                // Decrement counters for all ways except the accessed way
                for (i = 0; i < NINDEXES; i = i + 1) begin
                    if (i != index) begin
                        for (n = 0; n < NWAYS; n = n + 1) begin
                            if (recency[i][n * $clog2(NWAYS) +: $clog2(NWAYS)] > 0) begin
                                recency[i][n * $clog2(NWAYS) +: $clog2(NWAYS)] <= recency[i][n * $clog2(NWAYS) +: $clog2(NWAYS)] - 1;
                            end
                        end
                    end
                end
            end
        end
    end

    // Replacement logic to determine the LRU way
    assign way_replace = 0;
    always_comb begin
        // Initialize minimum counter value
        integer min_counter = $clog2(NWAYS);
        wire [$clog2(NWAYS)-1:0] min_counter_wire;

        // Find the way with the minimum counter
        for (i = 0; i < NINDEXES; i = i + 1) begin
            if (recency[i] != 0 && recency[i] < min_counter) begin
                min_counter = recency[i];
                min_counter_wire = index[i];
            end
        end

        // Assign the LRU way to way_replace
        if (min_counter_wire != 0) begin
            way_replace = min_counter_wire;
        end
    end

endmodule : lru_counter_policy

