output.rtl/coffee_machine.sv:
module coffee_machine #(
    parameter NBW_DLY    = 'd5,
    parameter NBW_BEANS  = 'd2,
    parameter NS_BEANS   = `ceil(log2(NBW_BEANS)),
    parameter NS_OP      = 3, // Fixed
    parameter NS_SENSOR  = 'd4  // Fixed
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [NBW_DLY-1:0]   i_grind_delay,
    input  logic [NBW_DLY-1:0]   i_heat_delay,
    input  logic [NBW_DLY-1:0]   i_pour_delay,
    input  logic [NBW_BEANS-1:0] i_bean_sel,
    input  logic [NS_OP-1:0]     i_operation_sel,
    input  logic                 i_start,
    input  logic [NS_SENSOR-1:0] i_sensor,
    output logic [NS_BEANS-1:0]  o_bean_sel,
    output logic                 o_grind_beans,
    output logic                 o_use_powder,
    output logic                 o_heat_water,
    output logic                 o_pour_coffee,
    output logic                 o_error
);

// Fixed delays (bean selection and powder usage)
localparam SEL_CYCLES    = NS_OP;
localparam POWDER_CYCLES = 2;

typedef enum logic [2:0] {
    IDLE     = 3'b000,
    BEAN_SEL = 3'b001,
    GRIND    = 3'b011,
    POWDER   = 3'b111,
    HEAT     = 3'b110,
    POUR     = 3'b100
} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NBW_DLY:0]     counter_ff, counter_nx;
logic [NBW_DLY-1:0]   grind_delay_ff, heat_delay_ff, pour_delay_ff;
logic [NS_OP-1:0]     operation_sel_ff;
logic [NS_BEANS-1:0] bean_sel_in_ff;
logic                 start_ff;

// Output assignment (error conditions)
always_comb begin : error_logic
    if(state_ff == IDLE) begin
        o_error = (i_sensor[0] | i_sensor[3]) | (&i_operation_sel[2:1]) | (i_operation_sel[1] & i_sensor[1]) | ((i_operation_sel == 3'b100 || i_operation_sel == 3'b001) & i_sensor[2]);
    end else begin
        o_error = i_sensor[3];
    end
end

// ----------------------------------------
// - Registers
// ----------------------------------------
always_ff @(posedge clk or negedge rst_async_n) begin : data_regs
    start_ff <= i_start & ~(i_sensor[0] | i_sensor[3]) & (|i_operation_sel[2:1]) & ~(i_operation_sel[1] & i_sensor[1]) & ~((i_operation_sel == 3'b100 || i_operation_sel == 3'b001) & i_sensor[2]) & (counter_nx == 0);

    if(i_start && state_ff == IDLE) begin
        operation_sel_ff <= i_operation_sel;
        grind_delay_ff   <= i_grind_delay;
        heat_delay_ff    <= i_heat_delay;
        pour_delay_ff    <= i_pour_delay;
        bean_sel_in_ff   <= i_bean_sel;
    end

    counter_ff      <= counter_nx;
end

always_ff @(posedge clk) begin : reset_regs
    if(~rst_async_n) begin
        state_ff <= IDLE;
    end else begin
        state_ff <= state_nx;
    end
end

// ----------------------------------------
// - FSM update
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            counter_nx = 0;

            if(start_ff) begin
                if(~(|i_operation_sel[2:1])) begin
                    state_nx = HEAT;
                end else if(i_operation_sel[1]) begin
                    state_nx = BEAN_SEL;
                end else if(i_operation_sel[0]) begin
                    state_nx = POUR;
                end else begin
                    state_nx = POWDER;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        BEAN_SEL: begin
            if(counter_ff >= SEL_CYCLES) begin
                counter_nx = 0;
                state_nx   = GRIND;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = BEAN_SEL;
            end
        end
        GRIND: begin
            if(counter_ff >= grind_delay_ff) begin
                counter_nx = 0;
                if(operation_sel_ff[0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = HEAT;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = GRIND;
            end
        end
        POWDER: begin
            if(counter_ff >= POWDER_CYCLES) begin
                counter_nx = 0;
                state_nx   = POUR;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        HEAT: begin
            if(counter_ff >= heat_delay_ff) begin
                counter_nx = 0;
                if(|operation_sel_ff[1:0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = POUR;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = HEAT;
            end
        end
        POUR: begin
            if(counter_ff >= pour_delay_ff) begin
                counter_nx = 0;
                state_nx   = IDLE;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        default: begin
            counter_nx = 0;
            state_nx   = IDLE;
        end
    endcase
end

// ----------------------------------------
// - Controller outputs
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_use_powder    = 1'b0;
            o_grind_beans   = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        BEAN_SEL: begin
            o_bean_sel                      = 1'b0; // Set all bits to 0
            o_bean_sel[bean_sel_in_ff]      = 1'b1; // Only the position of bean_sel_ff should be 1
            o_grind_beans                   = 1'b0;
            o_use_powder                    = 1'b0;
            o_heat_water                    = 1'b0;
            o_pour_coffee                   = 1'b0;
        end
        GRIND: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b1;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        POWDER: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b1;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        HEAT: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b1;
            o_pour_coffee   = 1'b0;
        end
        POUR: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b1;
        end
        default: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
    endcase
end

endmodule : coffee_machine

output.rtl/signed_comparator.sv:
module signed_unsigned_comparator #(parameter WIDTH = 5) (
    input logic i_enable,
    input logic i_mode,
    input logic [WIDTH-1:0] i_A,
    input logic [WIDTH-1:0] i_B,
    output logic o_greater,
    output logic o_less,
    output logic o_equal
);

    // Define internal signals
    logic [WIDTH-1:0] signed_A, signed_B;
    logic unsigned_A, unsigned_B;

    // Separate the inputs based on mode
    always_comb begin
        if (i_mode) begin
            // Signed mode: interpret MSB as sign bit
            signed_A = i_A;
            signed_B = i_B;
        end else begin
            // Magnitude mode: treat inputs as unsigned
            unsigned_A = i_A;
            unsigned_B = i_B;
        end

        // Convert to unsigned for magnitude mode comparison
        if (!i_mode) begin
            unsigned_A = {signed_A[WIDTH-1:0], 1'b0};
            unsigned_B = {signed_B[WIDTH-1:0], 1'b0};
        end
    end

    // Perform comparison
    always_comb begin
        if (i_enable) begin
            if (unsigned_A > unsigned_B) begin
                o_greater = 1'b1;
                o_less = 1'b0;
                o_equal = 1'b0;
            end else if (unsigned_A < unsigned_B) begin
                o_greater = 1'b0;
                o_less = 1'b1;
                o_equal = 1'b0;
            end else begin
                o_greater = 1'b0;
                o_less = 1'b0;
                o_equal = 1'b1;
            end
        end else begin
            o_greater = 1'b0;
            o_less = 1'b0;
            o_equal = 1'b0;
        end
    end
endmodule

output.rtl/complex_multiplier.sv:
module complex_multiplier (
    input clk,
    input arst_n,
    input [15:0] a_real,
    input [15:0] a_imag,
    input [15:0] b_real,
    input [15:0] b_imag,
    output reg [31:0] result_real,
    output reg [31:0] result_imag
);

    // Internal signals
    reg [31:0] real_result;
    reg [31:0] imag_result;

    // State machine for one cycle latency
    always @(posedge clk or posedge arst_n) begin
        if (arst_n) begin
            real_result <= 0;
            imag_result <= 0;
        end else if (!(arst_n)) begin
            // Real part calculation
            real_result <= (a_real * b_real) - (a_imag * b_imag);
            // Imaginary part calculation
            imag_result <= (a_real * b_imag) + (a_imag * b_real);
            // Output the results on the next clock cycle
            if (~arst_n) begin
                result_real <= real_result;
                result_imag <= imag_result;
            end
        end
    end

endmodule

output.rtl/compression_engine.sv:
module compression_engine (
  input   logic        clk,
  input   logic        reset,
  input   logic [23:0] num_i,
  output  logic [11:0] mantissa_o,
  output  logic [3:0]  exponent_o
);

  // --------------------------------------------------------
  // Internal wires and registers
  // --------------------------------------------------------
  logic [23:12] exp_oh;         // One-hot encoded exponent
  logic [3:0]   exp_bin;        // Binary exponent
  logic [3:0]   exponent;       // Adjusted exponent
  logic [11:0]  mantissa;       // Mantissa

  // --------------------------------------------------------
  // One-Hot Encoding of the Exponent
  // --------------------------------------------------------
  assign exp_oh[23] = num_i[23];

  // One-hot encoding of exp_oh
  integer i;
  always @(num_i) begin
    exp_oh = 12'b0;
    for (i = 23; i >= 0; i = i - 1) begin
      exp_oh[i] = num_i[i] & ~|num_i[23:i+1];
    end
  end

  // Use the `onehot_to_bin` module to convert one-hot to binary exponent
  onehot_to_bin #(
    .ONE_HOT_W(12),
    .BIN_W(4)
  ) exp_oh_bin (
    .oh_vec_i(exp_oh),
    .bin_vec_o(exp_bin)
  );

  assign exponent = (|exp_oh) ? exp_bin + 4'h1 : exp_bin;

  // --------------------------------------------------------
  // Mantissa Extraction Logic
  // --------------------------------------------------------
  // Extract the 12-bit mantissa based on `exponent`
  always @(exponent, num_i) begin
    if (num_i == 24'h000000) begin
      mantissa = 12'b0;
    end else if (exponent == 4'h0) begin
      mantissa = num_i[11:0];
    end else begin
      mantissa = num_i[exponent - 4'h1 : exponent * 4'h1 + 4'h11];
    end
  end

  // --------------------------------------------------------
  // Output assignments
  // --------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      exponent_o <= 4'd0;
      mantissa_o <= 12'd0;
    end else begin
      exponent_o <= exponent;
      mantissa_o <= mantissa;
    end
  end

endmodule

module onehot_to_bin #(
  parameter ONE_HOT_W = 12,  // Width of the one-hot input
  parameter BIN_W     = 4    // Width of the binary output
)(
  input   wire [ONE_HOT_W-1:0]  oh_vec_i,  // One-hot encoded input
  output  logic [BIN_W-1:0]     bin_vec_o  // Binary encoded output
);

  integer i;

  // Convert one-hot vector to binary
  assign bin_vec_o = {(ONE_HOT_W - BIN_W + 1) <= oh_vec_i, 1'b0};

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor(
    input i_clk,
    input i_rst_n,
    input i_enable,
    input i_clear,
    input i_ack,
    input i_fault,
    input [5:0] i_vector_1,
    input [5:0] i_vector_2,
    input [5:0] i_vector_3,
    input [5:0] i_vector_4,
    input [5:0] i_vector_5,
    input [5:0] i_vector_6,
    output reg o_ready,
    output reg o_error,
    output reg [2:0] o_fsm_status,
    output [7:0] o_vector_1,
    output [7:0] o_vector_2,
    output [7:0] o_vector_3,
    output [7:0] o_vector_4
);

    // State register
    reg [2:0] current_state, next_state;

    // Reset condition
    always @ (posedge i_clk or posedge i_rst_n) begin
        if (i_rst_n) begin
            current_state <= 3'b000;
            o_ready <= 0;
            o_error <= 0;
            o_fsm_status <= 3'b000;
            o_vector_1 <= 8'b0;
            o_vector_2 <= 8'b0;
            o_vector_3 <= 8'b0;
            o_vector_4 <= 8'b0;
        end else begin
            if (i_enable) begin
                current_state <= 3'b000;
            end
        end
    end

    // State transition logic
    always @ (posedge i_clk) begin
        case (current_state)
            3'b000: begin
                if (i_fault) begin
                    next_state <= 3'b111;
                end else begin
                    next_state <= 3'b001;
                end
            end
            3'b001: begin
                if (!i_fault) begin
                    next_state <= 3'b010;
                end else begin
                    next_state <= 3'b111;
                end
            end
            3'b010: begin
                if (!i_ack) begin
                    next_state <= 3'b000;
                end
            end
            3'b111: begin
                next_state <= 3'b000;
            end
        endcase
        current_state <= next_state;
    end

    // Process state logic
    always @ (current_state == 3'b001) begin
        if (!i_fault) begin
            o_vector_1 <= i_vector_1;
            o_vector_2 <= i_vector_2;
            o_vector_3 <= i_vector_3;
            o_vector_4 <= i_vector_4;
            o_fsm_status <= 3'b010;
        end
    end

    // Ready state logic
    always @ (current_state == 3'b010) begin
        if (!i_ack) begin
            o_fsm_status <= 3'b000;
        end else begin
            o_fsm_status <= 3'b010;
        end
        o_ready <= 1;
    end

    // Fault state logic
    always @ (current_state == 3'b111) begin
        if (i_clear && !i_fault) begin
            o_fsm_status <= 3'b000;
        end else begin
            o_error <= 1;
        end
    end

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(
    parameter DATA_WIDTH = 16,
    parameter COEFF_WIDTH = 16,
    parameter NUM_TAPS = 8
) (
    input clk,
    input reset,
    input [DATA_WIDTH * NUM_TAPS - 1:0] data_in,
    input valid_in,
    input [COEFF_WIDTH * NUM_TAPS - 1:0] coeffs,
    output reg [(DATA_WIDTH + COEFF_WIDTH + $clog2(NUM_TAPS) + 1) - 1:0] data_out,
    output reg valid_out
);

    // Internal signals
    reg [DATA_WIDTH * NUM_TAPS - 1:0] data_reg;
    reg [COEFF_WIDTH * NUM_TAPS - 1:0] coeffs_reg;
    reg [DATA_WIDTH + COEFF_WIDTH - 1:0] temp_sum;

    // Calculate intermediate multiplication width
    localparam NBW_MULT = DATA_WIDTH + COEFF_WIDTH;

    // Internal logic
    always @(posedge clk) begin
        if (reset) begin
            data_reg <= {DATA_WIDTH{1'b0}};
            coeffs_reg <= {COEFF_WIDTH{1'b0}};
            valid_out <= 1'b0;
        end else begin
            if (valid_in) begin
                data_reg <= data_in;
                coeffs_reg <= coeffs;
                valid_out <= 1'b1;
            end
        end
    end

    // Convolution operation
    always @(posedge clk) begin
        if (valid_in) begin
            // Element-wise multiplication
            for (int i = 0; i < NUM_TAPS; i++) begin
                temp_sum = temp_sum + data_reg[(i * DATA_WIDTH) +: DATA_WIDTH] * coeffs_reg[(NUM_TAPS - 1 - i) * COEFF_WIDTH +: COEFF_WIDTH];
            end
        end

        // Update output
        data_out <= temp_sum;
    end

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #(parameter N = 8, DATA_WIDTH = 16, DEC_FACTOR = 4)
(
    input clk,
    input reset,
    input valid_in,
    input [DATA_WIDTH * N - 1:0] data_in,
    output reg valid_out,
    output [DATA_WIDTH * (N / DEC_FACTOR) - 1:0] data_out,
    output [DATA_WIDTH - 1:0] peak_value
);

    reg [DATA_WIDTH - 1:0] decimated_data [N / DEC_FACTOR - 1:0];
    integer i;

    // Input Data Registering
    always @(posedge clk) begin
        if (reset) begin
            decimated_data <= {DATA_WIDTH{1'b0}};
        end else begin
            decimated_data <= {data_in[i * DATA_WIDTH +: DATA_WIDTH] for i in 0:N - 1};
        end
    end

    // Decimation
    always @(valid_in or decimated_data) begin
        if (valid_in) begin
            for (i = 0; i < N / DEC_FACTOR; i++) begin
                decimated_data[i] = decimated_data[i] ? decimated_data[i] : data_in[(i * DEC_FACTOR) * DATA_WIDTH +: DATA_WIDTH];
            end
        end
        valid_out = valid_in;
    end

    // Peak Detection
    always @(valid_in or decimated_data) begin
        if (valid_in) begin
            peak_value = decimated_data[0];
            for (i = 1; i < N / DEC_FACTOR; i++) begin
                if (decimated_data[i] > peak_value) begin
                    peak_value = decimated_data[i];
                end
            end
        end
    end

    // Output Packing
    assign data_out = {decimated_data[i] for i in 0:N / DEC_FACTOR - 1};

endmodule

output.rtl/sgd_linear_regression.sv:
module sgd_linear_regression #(
    parameter DATA_WIDTH = 16, 
    parameter LEARNING_RATE = 3'd1
) (
    input  logic clk,                               // Clock
    input  logic reset,                             // Asynchronous reset
    input  logic signed [DATA_WIDTH-1:0] x_in,      // Input data (x)
    input  logic signed [DATA_WIDTH-1:0] y_true,    // True output (target)
    output logic signed [DATA_WIDTH-1:0] w,     // Trained weight
    output logic signed [DATA_WIDTH-1:0] b      // Trained bias
);
    localparam NBW_PRED  = 2*DATA_WIDTH + 1;
    localparam NBW_ERROR = NBW_PRED + 1;
    localparam NBW_DELTA = 3 + NBW_ERROR + DATA_WIDTH;

    // Intermediate values
    logic signed [NBW_PRED-1:0] y_pred;  
    logic signed [NBW_ERROR-1:0] error;  
    logic signed [NBW_DELTA-1:0] delta_w; 
    logic signed [NBW_DELTA-1:0] delta_b;

    // Predicted output caculation
    always_comb begin
      y_pred = (w * x_in) + b;
    end

    // Error calculation
    always_comb begin
      error = y_true - y_pred;
    end

    // Weight and bias updates
    always_comb begin
      delta_w = LEARNING_RATE * error * x_in;
      delta_b = LEARNING_RATE * error;
    end

    // Registers for weight and bias
    logic signed [DATA_WIDTH-1:0] w_reg;
    logic signed [DATA_WIDTH-1:0] b_reg;

    // Register update
    always_ff begin : register_update
      if (reset) begin
        w_reg <= 0;
        b_reg <= 0;
      end else begin
        w_reg <= w;
        b_reg <= b;
      end
    end

    // Registers assignment
    assign w = w_reg;
    assign b = b_reg;

endmodule

output.rtl/fsm_linear_reg.sv:
module fsm_linear_reg #(parameter DATA_WIDTH = 16) (
    input clk,
    input reset,
    input start,
    input [DATA_WIDTH-1:0] x_in,
    input [DATA_WIDTH-1:0] w_in,
    input [DATA_WIDTH-1:0] b_in,
    output reg [2*DATA_WIDTH-1:0] result1,
    output reg [DATA_WIDTH:0] result2,
    output reg done
);

    typedef enum logic [1:0] {IDLE, COMPUTE, DONE} state_t;
    state_t state, next_state;

    // State transition logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
            result1 <= 0;
            result2 <= 0;
            done <= 0;
        end else begin
            case (state)
                IDLE:
                    if (start) begin
                        next_state = COMPUTE;
                    end else next_state = IDLE;
                COMPUTE:
                    result1 <= w_in * x_in >>> 1;
                    result2 <= b_in + (x_in >>> 2);
                    next_state = DONE;
                DONE:
                    done <= 1;
                    next_state = IDLE;
            endcase
            state <= next_state;
