    // Output logic
    always @* begin
        result1 <= {result1[DATA_WIDTH-1:0], 0}; // Prevent overflow
        result2 <= {result2[DATA_WIDTH-1:0], 0}; // Prevent overflow
        done <= (state == DONE);
    end

endmodule

