module data_width_converter(
    input clk,
    input reset,
    input [31:0] data_in,
    input data_valid,
    output reg [127:0] o_data_out,
    output reg o_data_out_valid
);

    // Internal signals
    reg [31:0] buffer[0:3];
    integer count = 0;

    // Reset condition
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            buffer[0] = 32'h00000000;
            count = 0;
            o_data_out_valid = 0;
        end else begin
            if (!data_valid) begin
                count <= 0;
            end else begin
                buffer[count] <= data_in;
                count <= count + 1;
                if (count == 4) begin
                    o_data_out <= {buffer[3], buffer[2], buffer[1], buffer[0]};
                    o_data_out_valid = 1;
                    count <= 0; // Reset the count for the next set of inputs
                end
            end
        end
    end

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc(
    input [39:0] data_in,
    input clk,
    input rst_n,
    output reg [39:0] data_out,
    output reg [1:0] dbi_cntrl
);

reg [20:0] prev_group_1, prev_group_0;

initial begin
    dbi_cntrl = 2'b00;
    data_out = 40'h0000_0000;
    prev_group_1 = 20'h0000_0000;
    prev_group_0 = 20'h0000_0000;
end

always @(posedge clk) begin
    if (rst_n) begin
        prev_group_1 <= 20'h0000_0000;
        prev_group_0 <= 20'h0000_0000;
        dbi_cntrl <= 2'b00;
        data_out <= 40'h0000_0000;
    end else begin
        if (prev_group_1 != data_in[39:20]) begin
            if (bit_count(data_in[39:20] ^ prev_group_1) > 10) begin
                dbi_cntrl[1] = 1'b1;
                data_out[39:20] = ~data_in[39:20];
            end else begin
                dbi_cntrl[1] = 1'b0;
                data_out[39:20] = data_in[39:20];
            end
        end

        if (prev_group_0 != data_in[19:0]) begin
            if (bit_count(data_in[19:0] ^ prev_group_0) > 10) begin
                dbi_cntrl[0] = 1'b1;
                data_out[19:0] = ~data_in[19:0];
            end else begin
                dbi_cntrl[0] = 1'b0;
                data_out[19:0] = data_in[19:0];
            end
        end

        prev_group_1 <= data_in[39:20];
        prev_group_0 <= data_in[19:0];
    end
end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Indicate data inversion enabled for each group 
   // Outputs
   output wire [39:0] data_out   // Output data after DBI logic
   );

   reg [39:0] group_0, group_1;

   // Splitting Incoming Data
   assign group_0 = data_in[39:20];
   assign group_1 = data_in[19:0];

   // Decoding the Data
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         group_0 <= 40'b0;
         group_1 <= 40'b0;
      end else begin
         if (dbi_cntrl == 2'b00) begin
            group_0 <= ~group_0;
         end
         if (dbi_cntrl == 2'b01) begin
            group_1 <= ~group_1;
         end
      end
   end

   // Combining Decoded Groups
   assign data_out = {group_0, group_1};

endmodule

