output.rtl/findfasterclock.sv:
`timescale 1ns/1ps

module FindFasterClock(
    input  wire clk_A,
    input  wire clk_B,
    input  wire rst_n,            // Active-low reset
    output reg  A_faster_than_B,  // 1 if clk_A is measured faster
    output reg  valid             // 1 once both clocks have measured a period
);

    //----------------------------------------
    // Internal signals
    //----------------------------------------
    reg        measure_B;          
    reg [31:0] b_count;            
    reg [31:0] periodA;            
    reg        done_A;             
    reg        measure_A;
    reg [31:0] a_count;
    reg [31:0] periodB;            
    reg        done_B;

    // A-domain FSM for measuring "periodA"
    reg [1:0] stateA;  
    localparam A_IDLE    = 2'd0,
               A_COUNT   = 2'd1,
               A_DONE    = 2'd2;
    // B-domain FSM for measuring "periodB"
    reg [1:0] stateB;
    localparam B_IDLE    = 2'd0,
               B_COUNT   = 2'd1,
               B_DONE    = 2'd2;

    // Clock A FSM
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            stateA <= A_IDLE;
            measure_B <= 0;
            b_count <= 0;
            periodA <= 0;
            done_A <= 0;
        end else begin
            case (stateA)
                A_IDLE: begin
                    // Transition to COUNT state
                    stateA <= A_COUNT;
                end
                A_COUNT: begin
                    // Capture b_count and transition to A_DONE
                    if (measure_B) begin
                        b_count <= b_count + 1;
                    end
                    if (b_count >= periodB) begin
                        stateA <= A_DONE;
                    end else begin
                        stateA <= A_COUNT;
                    end
                end
                A_DONE: begin
                    // Handle any optional reset or idle logic
                    if (!measure_B) begin
                        periodA <= b_count;
                        done_A <= 1;
                    end
                end
                default: stateA <= A_IDLE;
            endcase
        end
    end

    // Clock B FSM
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            stateB <= B_IDLE;
            measure_A <= 0;
            a_count <= 0;
            periodB <= 0;
            done_B <= 0;
        end else begin
            case (stateB)
                B_IDLE: begin
                    // Transition to COUNT state
                    stateB <= B_COUNT;
                end
                B_COUNT: begin
                    // Capture a_count and transition to B_DONE
                    if (measure_A) begin
                        a_count <= a_count + 1;
                    end
                    if (a_count >= periodA) begin
                        stateB <= B_DONE;
                    end else begin
                        stateB <= B_COUNT;
                    end
                end
                B_DONE: begin
                    // Handle any optional reset or idle logic
                    if (!measure_A) begin
                        periodB <= a_count;
                        done_B <= 1;
                    end
                end
                default: stateB <= B_IDLE;
            endcase
        end
    end

    // In B-domain, if measure_B=1, increment b_count on each B rising edge
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            b_count <= 0;
        end else if (measure_B) begin
            b_count <= b_count + 1;
        end
    end

    // In A-domain, if measure_A=1, increment a_count on each A rising edge
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            a_count <= 0;
        end else if (measure_A) begin
            a_count <= a_count + 1;
        end
    end

    // Combine results
    always @(*) begin
        if (!rst_n) begin
            valid = 0;
            A_faster_than_B = 0;
        end else begin
            valid = (done_A && done_B);
            if (valid) begin
                // Compare periodA and periodB
                A_faster_than_B = (periodA > periodB) ? 1 : 0;
            end else begin
                A_faster_than_B = 0;
            end
        end
    end

endmodule

output.rtl/SR_flipflop.sv:
module SR_flipflop(
    input i_S,        // Set input
    input i_R,        // Reset input
    input i_clk,      // Clock input
    input i_rst_b,    // Asynchronous active-low reset input
    output reg o_Q,   // Output Q
    output reg o_Q_b  // Inverted output Q
);

    // Always block triggered on the positive edge of the clock
    always @(posedge i_clk or negedge i_rst_b)
    begin
        if (!i_rst_b) // Asynchronous reset active-low
        begin
            o_Q <= 1'b0;  // Set output Q to 0
            o_Q_b <= 1'b1; // Set inverted output Q to 1
        end
        else
        begin
            // Set Q when i_S is high and i_R is low
            if (i_S && !i_R)
                o_Q <= 1'b1;
            // Reset Q when i_R is high and i_S is low
            else if (i_R && !i_S)
                o_Q <= 1'b0;
            // Hold Q when both i_S and i_R are low
            else if (!i_S && !i_R)
                o_Q <= o_Q; // Maintain previous state
            // Invalid state when both i_S and i_R are high
            else
                o_Q <= 1'b0; // Set Q to 0 (invalid state)
        end
    end

endmodule

output.rtl/fsm_seq_detector.sv:
module fsm_seq_detector(
    input clk_in,
    input rst_in,
    input [1:0] seq_in,
    output reg seq_detected
);

    logic [2:0] cur_state, next_state;
    logic seq_detected_w;

    enum state_t {S0, S1, S2, S3, S4, S5, S6, S7} state_t;

    // State transition logic
    always_comb begin
        case (cur_state)
            S0: next_state = seq_in == 1'b1 ? S1 : S0;
            S1: next_state = seq_in == 1'b1 ? S2 : S0;
            S2: next_state = seq_in == 1'b0 ? S3 : S0;
            S3: next_state = seq_in == 1'b1 ? S4 : S0;
            S4: next_state = seq_in == 1'b0 ? S5 : S0;
            S5: next_state = seq_in == 1'b1 ? S6 : S0;
            S6: next_state = seq_in == 1'b0 ? S7 : S0;
            S7: next_state = seq_in == 1'b1 ? S1 : S0;
            default: next_state = S0;
        endcase
    end

    // State register
    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            cur_state <= S0;
            seq_detected <= 0;
        end else begin
            cur_state <= next_state;
        end
    end

    // Output logic
    always_comb begin
        case (cur_state)
            S7: seq_detected_w = 1'b1;
            default: seq_detected_w = 1'b0;
        endcase
    end

    // Register the output
    always_ff @(posedge clk_in) begin
        seq_detected <= seq_detected_w;
    end

endmodule

