module hamming_rx #(parameter DATA_WIDTH = 4, parameter PARITY_BIT = 3) (
    input [ENCODED_DATA-1:0] data_in,
    output [DATA_WIDTH-1:0] data_out
);

  wire [PARITY_BIT-1:0] parity;
  wire error;

  // Initialize all internal registers to 0
  initial begin
    parity = {PARITY_BIT{1'b0}};
    error = 1'b0;
  end

  // Error detection using even parity logic
  // Rule for power-of-2 positions
  genvar i;
  always_comb begin
    for (i = 0; i < PARITY_BIT; i++) begin
      case (i)
        0: parity[0] = data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
        1: parity[1] = data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
        2: parity[2] = data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];
        default: parity[i] = 1'b0;
      endcase
    end

    // Error detection code
    error = (parity == {PARITY_BIT{1'b0}}) ? 1'b0 : 1'b1;
  end

  // Error correction
  always_comb begin
    if (error) begin
      // Calculate the error position
      int error_pos;
      for (error_pos = 0; error_pos < ENCODED_DATA; error_pos++) begin
        if (parity[PARITY_BIT-1:0] == {error_pos}) begin
          // Invert the erroneous bit
          data_in[error_pos] = ~data_in[error_pos];
          break;
        end
      end
    end
  end

  // Output assignment
  assign data_out = {data_in[3], data_in[5], data_in[6], data_in[7]};

endmodule

output.rtl/hamming_tx.sv:
module hamming_tx #(
    parameter DATA_WIDTH       = 64,
    parameter PART_WIDTH       = 4,
    parameter PARITY_BIT       = 3,
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1
)(
    input  [DATA_WIDTH-1:0]    data_in,
    output [ENCODED_DATA-1:0] data_out
);

    genvar i;

    for (i = 0; i < (DATA_WIDTH / PART_WIDTH); i = i + 1) begin : split_data
        t_hamming_tx #(.DATA_WIDTH(DATA_WIDTH / PART_WIDTH * PART_WIDTH),
                     .PARITY_BIT(PARITY_BIT),
                     .ENCODED_DATA(PART_WIDTH + PARITY_BIT + 1))
            t_hamming_tx_inst(.data_in(data_in[(i * PART_WIDTH) +: PART_WIDTH]),
                             .data_out(data_out[(i * (PART_WIDTH + PARITY_BIT + 1)) +: (PART_WIDTH + PARITY_BIT + 1)]));
    end

endmodule


module t_hamming_tx #(
    parameter DATA_WIDTH       = 4,
    parameter PARITY_BIT       = 3,
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1
)(
    input  [DATA_WIDTH-1:0]       data_in,
    output  reg[ENCODED_DATA-1:0] data_out
);

    reg [PARITY_BIT-1:0] parity;
    integer i, j, count;
    reg [$clog2(ENCODED_DATA)-1:0] pos;

    always @(*) begin
        data_out = {ENCODED_DATA{1'b0}};
        parity   = {PARITY_BIT{1'b0}};
        count    = 0;

        for (pos = 1; pos < ENCODED_DATA; pos = pos + 1) begin
            if (count < DATA_WIDTH) begin
                if ((pos & (pos - 1)) != 0) begin
                    data_out[pos] = data_in[count];
                    count = count + 1;
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            for (i = 1; i <= ENCODED_DATA-1; i = i + 1) begin
                if ((i & (1 << j)) != 0) begin
                    parity[j] = parity[j] ^ data_out[i];
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            data_out[(1 << j)] = parity[j];
        end
    end

endmodule

