                next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            C0_reg <= 15'b0; // Initialized to 15-bit zero
            C1_reg <= 15'b0;
            C2_reg <= 15'b0;
        end
        else begin
            case (current_state)
                COMPUTE: begin
                    temp0 <= (K00 * P0)%26 + (K01 * P1)%26 + (K02 * P2)%26;
                    temp1 <= (K10 * P0)%26 + (K11 * P1)%26 + (K12 * P2)%26;
                    temp2 <= (K20 * P0)%26 + (K21 * P1)%26 + (K22 * P2)%26;
                end
                COMPUTE_MOD: begin
                    C0_reg <= temp0%26;
