module load_store_unit (
    input clk,
    input rst_n,
    input ex_if_req_i,
    input [1:0] ex_if_type_i,
    input [31:0] ex_if_addr_base_i,
    input [31:0] ex_if_addr_offset_i,
    output reg ex_if_ready_o,
    output reg dmem_req_o,
    output reg dmem_req_we_o,
    output reg [3:0] dmem_req_be_o,
    output reg [31:0] dmem_req_addr_o,
    output reg [31:0] dmem_req_wdata_o,
    input dmem_rvalid_i,
    input [31:0] dmem_rsp_rdata_i,
    output reg wb_if_rvalid_o,
    output reg [31:0] wb_if_rdata_o
);

    // Internal signals
    reg [31:0] effective_addr_o;
    reg [3:0] byte_enable_o;
    reg [1:0] access_type_o;

    // Reset
    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            ex_if_ready_o <= 1'b1;
            dmem_req_o <= 1'b0;
            dmem_req_we_o <= 1'b0;
            dmem_req_be_o <= 3'b0;
            dmem_req_addr_o <= 32'h0;
            dmem_req_wdata_o <= 32'h0;
            wb_if_rvalid_o <= 1'b0;
            wb_if_rdata_o <= 32'h0;
        end else begin
            ex_if_ready_o <= 1'b0;
        end
    end

    // Transaction address calculation
    always @(posedge clk) begin
        if (ex_if_req_i) begin
            access_type_o = ex_if_type_i;
            effective_addr_o = ex_if_addr_base_i + ex_if_addr_offset_i;
            byte_enable_o = calculate_byte_enable(effective_addr_o, access_type_o);
        end
    end

    // Transaction request processing
    always @(posedge clk) begin
        if (ex_if_req_i && ex_if_ready_o) begin
            if (access_type_o == 0'b0 && is_aligned(effective_addr_o)) begin
                dmem_req_o <= 1'b1;
                dmem_req_we_o <= ex_if_req_i;
                dmem_req_addr_o <= effective_addr_o;
                dmem_req_be_o <= byte_enable_o;
                dmem_req_wdata_o <= 32'h0;
            end
        end

        // Store transaction
        if (ex_if_req_i && ex_if_req_we_o) begin
            dmem_req_we_o <= ex_if_req_we_o;
        end

        // Load transaction
        if (dmem_rvalid_i && ex_if_ready_o) begin
            wb_if_rvalid_o <= dmem_rvalid_i;
            wb_if_rdata_o <= dmem_rsp_rdata_i;
        end
    end

    // Byte enable calculation
    function [3:0] calculate_byte_enable(input [31:0] addr, input [1:0] type);
        [3:0] byte_enable;
        case (type)
            2'b10: byte_enable = {4'b0000, addr[31:2]}; // Halfword
            2'b01: byte_enable = {addr[31:2], addr[2:0]}; // Word
            2'b00: byte_enable = addr[31:0]; // Byte
            default: byte_enable = 4'b0000; // Misaligned access
        endcase
        return byte_enable;
    endfunction

    // Address alignment check
    function bool is_aligned(input [31:0] addr);
        return (addr[31:2] == 3'b00) || (addr[2:0] == 3'b00);
    endfunction

endmodule

input.rtl/load_store_unit.sv:
module load_store_unit (
    input  logic                 clk,
    input  logic                 rst_n,

    // EX stage interface
    input  logic                 ex_if_req_i,           // LSU request
    input  logic                 ex_if_we_i,            // Write enable: 0 (load), 1 (store)
    input  logic     [ 1:0]      ex_if_type_i,          // Data type: 0x2 (word), 0x1 (halfword), 0x0 (byte)
    input  logic     [31:0]      ex_if_wdata_i,         // Data to write to memory
    input  logic     [31:0]      ex_if_addr_base_i,     // Base address
    input  logic     [31:0]      ex_if_addr_offset_i,   // Offset address
    output logic                 ex_if_ready_o    ,

    // Writeback stage interface
    output logic     [31:0]      wb_if_rdata_o,         // Requested data
    output logic                 wb_if_rvalid_o,        // Requested data valid

    // Data memory (DMEM) interface
    output logic                 dmem_req_o,
    input  logic                 dmem_gnt_i,
    output logic     [31:0]      dmem_req_addr_o,
    output logic                 dmem_req_we_o,
    output logic     [ 3:0]      dmem_req_be_o,
    output logic     [31:0]      dmem_req_wdata_o,
    input  logic     [31:0]      dmem_rsp_rdata_i,
    input  logic                 dmem_rvalid_i
    );

  // Internal signals
  logic ex_req_fire;
  logic dmem_req_we_q;
  logic [31:0] data_addr_int;
  logic misaligned_addr;
  logic [3:0] dmem_be, dmem_req_be_q;

  logic busy_q;  // Sticky busy bit: Set with EX req and cleared with DMEM response
  logic dmem_req_q ;




  logic [31:0] dmem_req_wdata_q;
  logic [31:0] dmem_req_addr_q;

  logic [31:0] wb_if_rdata_q;
  logic wb_if_rvalid_q;

  // Address calculation
  assign data_addr_int = ex_if_addr_base_i + ex_if_addr_offset_i;

  // EX request fire condition
  assign ex_req_fire = ex_if_req_i && !busy_q && !misaligned_addr;
  assign ex_if_ready_o = !busy_q;

  ///////////////////////////////// Byte Enable Generation ////////////////////////////////
  always_comb begin
