module matrix_multiplier #(
  parameter ROW_A             = 4                                                   , // Number of rows in matrix A
  parameter COL_A             = 4                                                   , // Number of columns in matrix A
  parameter ROW_B             = 4                                                   , // Number of rows in matrix B
  parameter COL_B             = 4                                                   , // Number of columns in matrix B
  parameter INPUT_DATA_WIDTH  = 8                                                   , // Bit-width of input data
  parameter OUTPUT_DATA_WIDTH = (INPUT_DATA_WIDTH * 2) + $clog2(COL_A)                // Bit-width of output data
) (
  input  logic                                       clk      , // Clock input
  input  logic                                       srst     , // Active-high Synchronous reset
  input  logic                                       valid_in , // Indicates valid input matrices
  input  logic [ (ROW_A*COL_A*INPUT_DATA_WIDTH)-1:0] matrix_a , // Input matrix A in 1D form
  input  logic [ (ROW_B*COL_B*INPUT_DATA_WIDTH)-1:0] matrix_b , // Input matrix B in 1D form
  output logic                                       valid_out, // Indicates valid output matrix
  output logic [(ROW_A*COL_B*OUTPUT_DATA_WIDTH)-1:0] matrix_c   // Output matrix C in 1D form
);
  genvar gv1;
  genvar gv2;
  genvar gv3;

  generate
    logic [                                  COL_A:0] valid_out_reg; // Pipeline valid signal shift register
    logic [(ROW_A*COL_B*COL_A*OUTPUT_DATA_WIDTH)-1:0] mult_stage   ; // Intermediate multiplication results
    logic [(ROW_A*COL_B*COL_A*OUTPUT_DATA_WIDTH)-1:0] add_stage    ; // Accumulated addition results

    always_ff @(posedge clk)
      if (srst)
        {valid_out, valid_out_reg} <= '0;
      else
        {valid_out, valid_out_reg} <= {valid_out_reg, valid_in}; 

    for (gv1 = 0 ; gv1 < ROW_A ; gv1++) begin: row_a_gb
      for (gv2 = 0 ; gv2 < COL_B ; gv2++) begin: col_b_gb
        for (gv3 = 0 ; gv3 < COL_A ; gv3++) begin: col_a_gb
          always_ff @(posedge clk)
            if (srst)
              mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; 
            else
              mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= matrix_a[((gv1*COL_A)+gv3)*INPUT_DATA_WIDTH+:INPUT_DATA_WIDTH] * matrix_b[((gv3*COL_B)+gv2)*INPUT_DATA_WIDTH+:INPUT_DATA_WIDTH]; 


          always_ff @(posedge clk)
            if (srst)
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; 
            else if (gv3 == 0)
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH];
            else
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] + add_stage[((((gv1*COL_B)+gv2)*COL_A)+(gv3-1))*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH];
        end


        always_ff @(posedge clk)
          if (srst)
            matrix_c[((gv1*COL_B)+gv2)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; // Reset output matrix element
          else if (valid_out_reg[COL_A])
            matrix_c[((gv1*COL_B)+gv2)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= add_stage[((((gv1*COL_B)+gv2)*COL_A)+(COL_A-1))*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH]; // Set output to the accumulated result
      end
    end

  endgenerate

endmodule

output.rtl/cvdp_copilot_mem_allocator.sv:
module cvdp_copilot_mem_allocator #(
    parameter SIZE  = 4,
    parameter ADDRW = $clog2(SIZE)
) (
    input  wire             clk,
    input  wire             reset,

    input  wire             acquire_en,    
    output wire [ADDRW-1:0] acquire_addr,      

    input  wire             release_en,
    input  wire [ADDRW-1:0] release_addr,    

    output wire             empty,
    output wire             full    
);
    reg [SIZE-1:0] free_slots, free_slots_n;
    reg [ADDRW-1:0] acquire_addr_r;
    reg empty_r, full_r;    
    wire [ADDRW-1:0] free_index;
    wire full_d;

    // Leading zero counter instantiation
    cvdp_leading_zero_cnt #(
        // Parameters for leading zero counter
        DATA_WIDTH = SIZE,
        REVERSE = 0
    ) free_slots_sel (
        .data   (free_slots_n),
        .leading_zeros  (free_index),
        .all_zeros (full_d)
    ); 

    // Memory allocation logic
    always @ (posedge clk) begin
        if (reset) begin
            free_slots <= {SIZE{1'b1}}; // All slots free
            acquire_addr_r <= 0; // No available address
            empty_r <= 1; // All slots are free
            full_r <= 0; // No slots fully occupied
        end else begin
            if (acquire_en) begin
                free_slots_n <= free_slots ^ (release_addr[ADDRW-1:0] << (SIZE-1)); // Mark slot as free
                acquire_addr_r <= free_index; // Get next available address
                empty_r <= (free_slots == {SIZE{1'b1}}); // Check if all slots are free
                full_r <= (free_slots == 0); // Check if all slots are occupied
            end
        end
    end

    assign acquire_addr = acquire_addr_r;
    assign empty = empty_r;
    assign full = full_r;

endmodule

output.rtl/microcode_sequencer.sv:
module microcode_sequencer(
    input clk,
    input c_n_in,
    input c_inc_in,
    input r_en,
    input cc,
    input ien,
    input d_in[3:0],
    input instr_in[4:0],
    output reg d_out[3:0],
    output reg c_n_out,
    output reg c_inc_out,
    output reg full,
    output reg empty
);

    wire stack_push, stack_pop, stack_we, stack_mux_sel;
    wire pc_mux_sel;
    wire a_mux_sel[1:0], b_mux_sel[1:0];

    wire [4:0] stack_data_out, aux_reg_out, a_mux_out, b_mux_out, full_adder_out;

    // Instruction Decoder
    logic cen, rst, inc, pc_mux_sel, a_mux_sel, b_mux_sel;

    instruction_decoder #(.cc_in(cc), .ien(ien), .oen(r_en)) .
    (
        cen, rst, inc, pc_mux_sel, a_mux_sel, b_mux_sel,
        stack_push, stack_pop, stack_we, stack_mux_sel
    );

    // Stack Management
    lifo_stack #(.stack_data_mux_sel(stack_mux_sel), .stack_we(stack_we), .stack_re(full | empty)) .
    (
        stack_data_out, full, empty
    );

    // Program Counter
    program_counter #(.pc_mux_sel(pc_mux_sel), .inc(inc)) .
    (
        pc_out, pc_c_out
    );

    // Arithmetic Operations
    microcode_arithmetic #(.a_mux_sel(a_mux_sel), .b_mux_sel(b_mux_sel), .aux_reg_out(aux_reg_out), .arith_cout(full_adder_out)) .
    (
        d_out, arith_cout
    );

    // Logic
    assign d_out = (ien) ? aux_reg_out : 4'b0000;
    assign c_n_out = c_n_in;
    assign c_inc_out = c_inc_in;
    assign full = full_adder_out | (ien & stack_push);
    assign empty = !empty & stack_pop;

endmodule

input.rtl/signed_sequential_booth_multiplier.s:
module signed_sequential_booth_multiplier #(parameter WIDTH = 8) (
    input  wire signed [WIDTH-1:0] A,
    input  wire signed [WIDTH-1:0] B,
    input  wire clk,
    input  wire rst,
    input  wire start,
    output reg  signed [2*WIDTH-1:0] result,
    output reg done
);

    // FSM states
    typedef enum logic [2:0] {
        IDLE     = 3'b000,
        ENCODE   = 3'b001, 
        PARTIAL  = 3'b010, 
        ADDITION = 3'b011, 
        DONE     = 3'b100
    } state_t;

    state_t state, next_state;

    // Registers for control and data signals
    reg signed [2*WIDTH-1:0] partial_products [0:WIDTH/2-1];
    reg signed [2*WIDTH-1:0] multiplicand;
    reg signed [WIDTH:0] booth_bits; 
    reg signed [2*WIDTH-1:0] accumulator;  
    reg [2:0] encoding_bits [0:WIDTH/2-1];
    reg [$clog2(WIDTH/2):0] addition_counter; // Counter for addition cycles
    integer i;

    // State machine: Sequential process for state transitions
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // State machine: Combinational process for next-state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (start) begin
                    next_state = ENCODE;
                end else begin
                    next_state = IDLE;
                end
            end

            ENCODE: begin
                next_state = PARTIAL;
            end

            PARTIAL: begin
                next_state = ADDITION;
            end

            ADDITION: begin
                next_state = DONE;
            end

            DONE: begin
                if (!start) begin
                    next_state = IDLE;
                end else begin
                    next_state = DONE;
                end
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // Signal assignments: Perform operations based on current state
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            done <= 0;
            result <= 0;
            accumulator <= 0;
            addition_counter <= 0;
            multiplicand <= 0;
            booth_bits <= 0;
            for (i = 0; i < WIDTH/2; i = i + 1) begin
                encoding_bits[i] <= 0;
                partial_products[i] <= 0;
            end
        end else begin
            case (state)
                IDLE: begin
                    // Prepare for new computation
                    done <= 0;
                    result <= 0;
                    if (start) begin
                        multiplicand <= {{(WIDTH){A[WIDTH-1]}}, A}; // Sign-extend A
                        booth_bits <= {B, 1'b0};
                        accumulator <= 0;
                        for (i = 0; i < WIDTH/2; i = i + 1) begin
                            partial_products[i] <= 0;
                        end
                    end
                end

                ENCODE: begin
                    // Extract 3-bit Booth segments
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        encoding_bits[i] <= booth_bits[2*i +: 3];
                    end
                end

                PARTIAL: begin
                    // Generate partial products based on Booth encoding
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        case (encoding_bits[i])
                            3'b001, 3'b010: partial_products[i] <= (multiplicand << (2 * i));
                            3'b011:         partial_products[i] <= ((multiplicand << 1) << (2 * i));
                            3'b100:         partial_products[i] <= -((multiplicand << 1) << (2 * i));
                            3'b101, 3'b110: partial_products[i] <= -(multiplicand << (2 * i));
                            default:        partial_products[i] <= 0;
                        endcase
                    end
                end

                ADDITION: begin
                    accumulator <= 0;
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                      accumulator <= accumulator + partial_products[i];  
                    end
                end

                DONE: begin
                    // Output the result
                    result <= accumulator;
                    done <= 1;
                end
            endcase
        end
    end
endmodule

module pipelined_modified_booth_multiplier (
    input clk,
    input rst,
    input start,
    input signed [15:0] X,
    input signed [15:0] Y,
    output reg signed  [31:0] result,
    output reg done
);

    reg signed [31:0] partial_products [0:7];
    reg signed [15:0] X_reg, Y_reg;
    reg [4:0] valid_reg; // Extended valid register for more granular state control

    integer i;

    // Registers for pipelining the addition stages
    reg signed [31:0] s1, s2, s3, s4;
    reg signed [31:0] temp_products1, temp_products2;

    always @(posedge clk or posedge rst) 
    begin
        if (rst) 
        begin
            X_reg <= 16'd0;
            Y_reg <= 16'd0;
            valid_reg <= 5'd0;
            done <= 0;
            for (i = 0; i < 8; i = i + 1) 
            begin
                partial_products[i] <= 32'd0;
            end
            s1 <= 0; s2 <= 0; s3 <= 0; s4 <= 0;
            temp_products1 <= 0; temp_products2 <= 0;
            result <= 32'd0;
            done <= 1'b0;
        end 
        else 
        begin
            if (start && !valid_reg[0]) begin
                X_reg <= X;
                Y_reg <= Y;
                valid_reg[0] <= 1;  // Initiate state 1
            end
            else
              valid_reg[0] <= 0;  // Initiate state 1 

            // Process Booth multiplication
            if (valid_reg[0]) begin
                for (i = 0; i < 8; i = i + 1) begin
                    case ({Y_reg[2*i+1], Y_reg[2*i], (i == 0) ? 1'b0 : Y_reg[2*i-1]})
                        3'b000, 3'b111: partial_products[i] <= 32'd0;
                        3'b001, 3'b010: partial_products[i] <= {{16{X_reg[15]}}, X_reg} >> (2*i);
                        3'b011: partial_products[i] <= {{16{X_reg[15]}}, X_reg} >> (2*i + 1);
                        3'b100: partial_products[i] <= -({{16{X_reg[15]}}, X_reg} >> (2*i + 1));
                        3'b101, 3'b110: partial_products[i] <= -({{16{X_reg[15]}}, X_reg} >> (2*i));
                        default: partial_products[i] <= 32'd0;
                    endcase
                end
                valid_reg[1] <= 1; // State 1 done, mark State 2 as ready
                valid_reg[0] <= 0; // Reset state 1 active flag
            end 
            else
              valid_reg[1] <= 0; // State 1 done, mark State 2 as ready

            // State 3: Partial Summation
            if (valid_reg[1]) begin 
                s1 <= partial_products[0] + partial_products[1] + partial_products[2];
                s2 <= partial_products[3] + partial_products[4] + partial_products[5];

                valid_reg[2] <= 1; // State 3 done, mark State 4 as ready
                valid_reg[1] <= 0; // Clear state 2 active flag
            end 
            else
              valid_reg[2] <= 0; // State 3 done, mark State 4 as ready 

            // State 4: Sum of Sums
            if (valid_reg[2]) begin 
                s3 <= s1 + s2;
                s4 <= partial_products[6] + partial_products[7];

                valid_reg[3] <= 1; // State 4 done, mark State 5 as ready
                valid_reg[2] <= 0; // Clear state 3 active flag
            end 
            else
              valid_reg[3] <= 0; // State 4 done, mark State 5 as ready


            // State 5: Final Result
            if (valid_reg[3]) begin
                result <= s3 + s4;
                done <= 1;  // Output done signal
                valid_reg[3] <= 0; // Reset state 5 active flag after result computation
            end 
            else
            begin
              result <= 0;
              done <= 1'b0; 
            end 

        end
    end

endmodule

