module neuromorphic_array #(
    parameter NEURONS = 8,       // Number of neurons
    parameter INPUTS = 8,        // Number of inputs
    parameter OUTPUTS = 8         // Number of outputs
) (
    input  logic [7:0] ui_in,       // Control input
    input logic [7:0] uio_in,      // Input data
    output logic [7:0] uo_out,     // Output data
    input logic clk,                // Clock
    input logic rst_n               // Reset
);
    // Internal wires for neuron outputs
    logic [7:0] neuron_outputs [0:NEURONS-1];

    // Instantiate the neurons
    genvar i;
    generate
        for (i = 0; i < NEURONS; i = i + 1) begin : neuron_instantiation
            single_neuron_dut dut_neuron
                (.clk(clk),
                 .rst_n(rst_n),
                 .control(ui_in[0]),
                 .seq_in(uio_in),
                 .seq_out(neuron_outputs[i]));
        end
    endgenerate

    // Combine outputs from the last neuron
    assign uo_out = neuron_outputs[NEURONS-1]; // Output from the last neuron

endmodule

module single_neuron_dut (
    input logic clk,
    input logic rst_n,
    input logic control,        // Control signal
    input logic [7:0] seq_in,   // Input sequence
    output logic [7:0] seq_out   // Output sequence
);
    logic state;
    // Reset logic
    always @ (posedge clk or negedge rst_n) begin
        if (rst_n)
            state <= 8'd0;
        else
            state <= seq_in;
    end
    // Update logic
    always @ (posedge clk or posedge control) begin
        if (control)
            state <= seq_in;
        else
            state <= state;
    end
    // Output logic
    assign seq_out = state;
endmodule

input.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 3'b000, REGION_A = 3'b001, REGION_B = 3'b010} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = (config_ff[1] & ~config_ff[0]);
assign B_to_A = (config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 3'b0;
                region_B_nx[NS_B] = 3'b0;
            end

            region_A_nx[NS_A-2:0] = {3'b0};
            region_B_nx[NS_B-2:0] = {3'b0};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 3'b0;
            end
            region_B_nx[NS_B-2:0] = {3'b0};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 3'b0;
            end
            region_A_nx[NS_A-2:0] = {3'b0};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {3'b0};
            region_B_nx = {3'b0};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/packet_controller.sv:
module packet_controller(
    input clk,
    input rst,
    input rx_valid_i,
    input [7:0] rx_data_8_i,
    output tx_start_o,
    output reg [7:0] tx_data_8_o
);

    // State encoding
    typedef enum logic [2:0] {
        S_IDLE,
        S_GOT_8_BYTES,
        S_RECV_CHECKSUM,
        S_BUILD_RESPONSE,
        S_SEND_FIRST_BYTE,
        S_RESPONSE_READY
    } state_t;

    // State register
    reg [2:0] current_state, next_state;

    // Packet buffer
    reg [15:0] packet_buffer [0:5];

    // FSM variables
    logic [7:0] header;
    logic [15:0] num1, num2, opcode, checksum;
    logic valid_packet;

    // State transition logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state <= S_IDLE;
            packet_buffer <= 0;
            valid_packet <= 0;
        end else begin
            current_state <= next_state;
        end
    end

    // State transition assignments
    always @(current_state or rx_valid_i or rx_data_8_i) begin
        case (current_state)
            S_IDLE: begin
                if (rx_valid_i) begin
                    if (rx_data_8_i == 16'hBACD) begin
                        next_state <= S_GOT_8_BYTES;
                        packet_buffer <= rx_data_8_i;
                    end else begin
                        valid_packet <= 0;
                    end
                end
            end
            S_GOT_8_BYTES: begin
                packet_buffer <= {packet_buffer[4:0], rx_data_8_i};
                if (rx_data_8_i == 16'hBACD) begin
                    next_state <= S_RECV_CHECKSUM;
                end else begin
                    valid_packet <= 0;
                end
            end
            S_RECV_CHECKSUM: begin
                header = packet_buffer[15:8];
                num1 = packet_buffer[11:4];
                num2 = packet_buffer[9:0];
                opcode = packet_buffer[7];
                checksum = packet_buffer[6] + packet_buffer[5] + packet_buffer[4] + packet_buffer[3] + packet_buffer[2] + packet_buffer[1] + packet_buffer[0];
                if (header == 16'hBACD && (checksum == 0)) begin
                    next_state <= S_BUILD_RESPONSE;
                end else begin
                    next_state <= S_IDLE;
                end
            end
            S_BUILD_RESPONSE: begin
                num1 <= num1;
                num2 <= num2;
                opcode <= opcode;
                // Calculate checksum for response packet
                checksum = num1 + num2 + 8'h01;
                if (checksum == 0) begin
                    next_state <= S_SEND_FIRST_BYTE;
                end else begin
                    next_state <= S_IDLE;
                end
            end
            S_SEND_FIRST_BYTE: begin
                tx_start_o = 1'b1;
                tx_data_8_o <= 16'hABCD;
                tx_data_8_o <= num1;
                next_state <= S_RESPONSE_READY;
            end
            S_RESPONSE_READY: begin
                tx_start_o = 1'b0;
                tx_data_8_o <= num1 + num2;
                next_state <= S_IDLE;
            end
            default: next_state <= S_IDLE;
        endcase
    end

    // Output logic
    assign tx_start_o = current_state == S_SEND_FIRST_BYTE;
    always @(posedge clk) begin
        if (current_state == S_RESPONSE_READY) begin
            tx_data_8_o <= num1 + num2;
        end
    end

endmodule

output.rtl/password_generator.sv:
module password_generator #(
    parameter WIDTH = 4  
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];  
  logic [7:0] counter;  
  logic [1:0] char_type; 

  integer i;

  // Counter Logic for pseudo-random generation
  always_ff @(posedge clk) begin
    if (reset) begin
      counter <= 8'd0;
      char_type <= 2'b00;
    end else begin
      counter <= counter + 1;
      char_type <= (counter MOD 4) + 2'b00;
    end
  end

  // Generate password characters
  always_comb begin
    for (i = 0; i < WIDTH; i = i + 1) begin
      case (char_type)
        2'b00: char_array[i] = ((counter + char_array[(i+1)%WIDTH]) % 26) + 8'd97;
        2'b01: char_array[i] = ((counter + i) % 26) + 8'd65;
        2'b10: char_array[i] = ((counter + char_array[(i+WIDTH-1)%WIDTH]) % 14) + 8'd33;
        2'b11: char_array[i] = ((counter + i) % 10) + 8'd48;
      endcase
    end
  end

  // Pack the char_array into the password signal
  assign password = {(WIDTH-1:0){char_array}};

endmodule

