    if (!reset)
        byte_cnt <= 0;
    else if (curr_state == S_ACTIVE)
        byte_cnt <= byte_cnt + 1;
end

always_comb begin
    case (curr_state)
        S_ACTIVE: 
            if (byte_cnt < PKT_BYTES) begin
                pkt_reg <= {pkt_reg, data_in};
            end else begin
                byte_cnt <= 0; // Reset byte counter after packet is fully captured
            end
