always @(posedge aclk) begin
    if (!aresetn) begin
        read_ptr <= 0;
    end else if (fifo_read) begin
        // Update FIFO read pointer only after register computations
        if (!empty) begin
            read_ptr <= read_ptr + 1;
        end
    end
end

