module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output // 4-bit output
);

integer i;
reg [3:0] sum;  

always @(posedge clk or posedge reset) begin
    if (reset) begin
        correlation_output <= 0;
        sum = 0;  
    end else begin
        sum = 0;  
        for (i = 0; i < 8; i = i + 1) begin
            sum = sum + (input_signal[i] & reference_signal[i]); 
        end
    end
end

endmodule

output.rtl/signal_correlator.sv:
module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output // 4-bit output
);

integer i;
reg [3:0] sum;  

always @(posedge clk or posedge reset) begin
    if (reset) begin
        correlation_output <= 0;
        sum = 0;  
    end else begin
        sum = 0;  
        for (i = 0; i < 8; i = i + 1) begin
            sum = sum + (input_signal[i] & reference_signal[i]) * 2; 
        end
        if (sum > 15'd15) begin
            sum <= 15'd15; // Clamping to ensure sum stays within 4-bit range
        end
        correlation_output <= sum;
    end
end

endmodule

output.rtl/signedadder.v:
module signedadder #(parameter DATA_WIDTH = 8)(
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);
    // Internal registers
    reg [DATA_WIDTH-1:0] a_reg, b_reg;
    reg [1:0] status;
    reg overflow_flag;

    // State machine
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            status <= 0;
            a_reg <= 0;
            b_reg <= 0;
            o_overflow <= 0;
            o_resultant_sum <= 0;
            o_ready <= 0;
        end else begin
            case (status)
                0: begin
                    if (i_start) begin
                        a_reg <= i_operand_a;
                        b_reg <= i_operand_b;
                        status <= 1;
                    end
                end
                1: begin
                    if (i_enable) begin
                        if (i_mode == 0) begin
                            o_resultant_sum <= a_reg + b_reg;
                            overflow_flag = (a_reg[DATA_WIDTH-1] & b_reg[DATA_WIDTH-1]) |
                                            ((!a_reg[DATA_WIDTH-1]) & (b_reg[DATA_WIDTH-1] ^ a_reg[DATA_WIDTH-1]));
                        end else if (i_mode == 1) begin
                            o_resultant_sum <= a_reg - b_reg;
                            overflow_flag = (a_reg[DATA_WIDTH-1] ^ b_reg[DATA_WIDTH-1]) |
                                            (!a_reg[DATA_WIDTH-1] & b_reg[DATA_WIDTH-1]);
                        end
                        o_overflow <= overflow_flag;
                        o_ready <= 1;
                        status <= 11;
                    end
                end
                11: begin
                    o_overflow <= overflow_flag;
                    o_ready <= 1;
                    status <= 0;
                end
            endcase
        end
    end

    // Output logic
    assign o_resultant_sum = (i_clear) ? 0 : o_resultant_sum;
    assign o_overflow = (i_clear) | o_overflow;
    assign o_ready = (i_clear) | o_ready;

endmodule

output.rtl/spi_fsm.v:
module spi_fsm (
    input  wire         i_clk,       // System clock
    input  wire         i_rst_b,     // Active-low async reset
    input  wire [15:0]  i_data_in,   // Parallel 16-bit data to transmit
    input  wire         i_enable,    // Enable block
    input  wire         i_fault,     // Fault indicator
    input  wire         i_clear,     // Forces FSM to clear/idle

    output reg          o_spi_cs_b,  // SPI chip select (active-low)
    output reg          o_spi_clk,   // SPI clock
    output reg          o_spi_data,  // Serialized SPI data out
    output reg [4:0]    o_bits_left, // Bits left to transmit
    output reg          o_done,      // Single-cycle pulse when done or error
    output reg [1:0]    o_fsm_state  // FSM state for external monitoring
);

    // Internal signals
    reg [1:0] internal_fsm_state;
    reg [4:0] internal_bits_left;

    // State transition logic
    always @(posedge i_clk or negedge i_rst_b) begin
        if (!i_rst_b) begin
            internal_fsm_state <= 2'b00; // Idle
            o_spi_cs_b <= 1;
            o_spi_clk <= 0;
            o_spi_data <= 0;
            o_bits_left <= 10;
            o_done <= 0;
        end else if (i_enable) begin
            case (internal_fsm_state)
                2'b00: begin
                    internal_fsm_state <= 2'b01; // Transmit
                    o_spi_cs_b <= 0;
                    o_spi_clk <= 0;
                    o_spi_data <= i_data_in[15];
                    o_bits_left <= 15;
                end
                2'b01: begin
                    internal_fsm_state <= 2'b10; // Clock Toggle
                    o_spi_clk <= ~o_spi_clk;
                    if (internal_bits_left == 0) begin
                        internal_fsm_state <= 2'b00; // Idle
                        o_spi_clk <= 0;
                        o_spi_cs_b <= 1;
                        o_done <= 1;
                    end
                    internal_bits_left <= internal_bits_left - 1;
                end
                2'b10: begin
                    internal_fsm_state <= (internal_fsm_state == 2'b10) ? 2'b00 : internal_fsm_state; // Error or Idle
                    o_spi_clk <= 0;
                    o_spi_data <= 0;
                    o_done <= 0;
                end
            endcase
        end
    end

    // Fault handling
    always @(i_fault or i_clear) begin
        if (i_fault) begin
            internal_fsm_state <= 2'b11;
            o_spi_cs_b <= 1;
            o_spi_clk <= 0;
            o_spi_data <= 0;
            o_bits_left <= 10;
            o_done <= 0;
        end
        if (i_clear) begin
            internal_fsm_state <= 2'b00;
            o_spi_cs_b <= 1;
            o_spi_clk <= 0;
            o_spi_data <= 0;
            o_bits_left <= 10;
            o_done <= 0;
        end
    end

    // Output logic
    always @(internal_fsm_state) begin
        o_fsm_state = internal_fsm_state;
    end

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #(
    parameter p_bit_width = 8,
    parameter p_max_numbers = 16
) (
    input wire i_clk,
    input wire i_rst_n,
    input wire i_ready,
    input wire [p_bit_width-1:0] i_number,
    output reg [p_bit_width-1:0] o_unique_number
);

    // Internal registers
    reg [p_bit_width-1:0] number_counter [0:p_max_numbers-1];
    reg [p_bit_width-1:0] number_count [0:p_max_numbers-1];
    reg [p_bit_width-1:0] unique_number;

    // State machine
    always @(posedge i_clk or posedge i_rst_n) begin
        if (i_rst_n) begin
            // Reset all counters and unique number
            number_counter <= {p_max_numbers{1'b0}};
            number_count <= {p_max_numbers{1'b0}};
            unique_number <= 0;
        end else if (i_ready) begin
            // Increment counters based on input number
            number_counter <= number_counter + {i_number{1'b1}};
            number_count <= number_count + 1;

            // Identify unique number
            if (number_count[number_counter] == 1) begin
                unique_number <= i_number;
            end
        end
    end

    // Output logic
    always @(o_unique_number) begin
        o_unique_number <= unique_number;
    end

endmodule

