           state <= IDLE;
           data_array <= { {WIDTH{1'b0}}, {WIDTH{1'b0}}, {WIDTH{1'b0}}, {WIDTH{1'b0}} };
           done <= 1'b0;
       end else if (start) begin
           state <= LOAD;
       end
   end

   // Sorting Engine
   always @(posedge clk) begin
       case (state)
           IDLE: begin
               if (start) begin
                   state <= SORT;
                   pass_cnt <= 1;
                   pair_idx <= 0;
