                       6: begin
                           if ((data_array[pair_idx] > data_array[pair_idx + 1]) == 1'b1) begin
                               data_array[pair_idx] <= data_array[pair_idx + 1];
                           end
                           pass_cnt <= pass_cnt + 1;
                       end
                       7: begin
                           if ((data_array[pair_idx + 1] > data_array[pair_idx + 2]) == 1'b1) begin
                               data_array[pair_idx + 1] <= data_array[pair_idx + 2];
                           end
                           pass_cnt <= 1;
                       end
                       8: begin
                           done <= 1'b1;
                           state <= DONE;
                       end
                   end
               end else begin
                   state <= SORT;
                   pair_idx <= pair_idx + 1;
               end
           end
           DONE: begin
               out_data <= data_array;
