    always @(posedge clk) begin
        if(rinc_out) 
            bp <= 4'b0;
        else 
            if(rinc_in & ~rempty_out) 
               bp <= bp + 1'b1;
    end

    //Other comb logic

    assign rde = bp[3];
    assign o_bit = byte_buf[bp];

endmodule

input.rtl/square_root.sv:
module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16) (
    input  wire clk,
    input  wire rst,
    input  wire start,
    input  wire [WIDTH-1:0] num,
    output reg [WIDTH/2-1:0] final_root,
    output reg done
);
    reg [WIDTH-1:0] remainder, temp_root;
    reg [WIDTH-1:0] odd;
    reg [WIDTH/2-1:0] test_bit;
    integer i;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            final_root <= 0;
            done <= 0;
            odd <= 1;
            remainder <= num;
        end else begin
            if (start) begin
                if (done) begin
                    final_root <= 0;
                    odd <= 1;
                    remainder <= num;
                    done <= 0;
                end
                else begin
                    done <= 1;
                end
            end

            if (done) begin
                final_root <= remainder;
                done <= 0;
            end

            if (remainder >= odd) begin
                temp_root <= remainder - odd;
                odd <= odd + 2;
                final_root <= final_root + 1;
            end

            if (temp_root < remainder) begin
                done <= 1;
                final_root <= temp_root;
            end
        end
    end
endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict(
    input [31:0] fetch_rdata_i,
    input [31:0] fetch_pc_i,
    input fetch_valid_i,
    output reg [1:0] predict_branch_taken_o,
    output [31:0] predict_branch_pc_o
);

    reg [31:0] imm_b_type, imm_cj_type, imm_j_type, imm_cb_type;

    parameter OPCODE_BRANCH = 7'h63;
    parameter OPCODE_JAL = 7'h6F;
    parameter OPCODE_JALR = 7'h67;

    always @(fetch_rdata_i) begin
        case (fetch_rdata_i[31:0])
            OPCODE_JAL: imm_j_type = fetch_rdata_i;
            OPCODE_JALR: imm_j_type = fetch_rdata_i;
            OPCODE_BRANCH: imm_b_type = fetch_rdata_i;
            default: imm_b_type = 32'h00000000;
        endcase
    end

    always @(fetch_rdata_i) begin
        case (fetch_rdata_i[31:0])
            OPCODE_JAL: imm_cj_type = 32'h00000000;
            OPCODE_JALR: imm_cj_type = fetch_rdata_i;
            OPCODE_BRANCH: imm_cb_type = fetch_rdata_i;
            default: imm_cb_type = 32'h00000000;
        endcase
    end

    assign imm_j_type = (fetch_rdata_i == OPCODE_JAL) | (fetch_rdata_i == OPCODE_JALR);
    assign imm_b_type = (fetch_rdata_i == OPCODE_BRANCH);
    assign imm_cj_type = (fetch_rdata_i == OPCODE_JAL) | (fetch_rdata_i == OPCODE_JALR);
    assign imm_cb_type = (fetch_rdata_i == OPCODE_BRANCH);

    assign instr = fetch_rdata_i;
    assign instr_j = imm_j_type;
    assign instr_b = imm_b_type;
    assign instr_cj = imm_cj_type;
    assign instr_cb = imm_cb_type;

    // Sign extension for immediate values
    assign imm_j_type_se = {31'b0, imm_j_type[30:0], {1'b0, imm_j_type[31]}};
    assign imm_b_type_se = {31'b0, imm_b_type[30:0], {1'b0, imm_b_type[31]}};
    assign imm_cj_type_se = {31'b0, imm_cj_type[30:0], {1'b0, imm_cj_type[31]}};
    assign imm_cb_type_se = {31'b0, imm_cb_type[30:0], {1'b0, imm_cb_type[31]}};

    // Prediction logic
    always @(fetch_valid_i) begin
        if (fetch_valid_i) begin
            predict_branch_taken_o = (instr_b | instr_cj) & instr_b_taken;
            predict_branch_pc_o = fetch_pc_i + imm_b_type_se;
        end else begin
            predict_branch_taken_o = 1'b0;
            predict_branch_pc_o = 32'h00000000;
        end
    end

    // Determine if branch is taken based on sign of offset
    always @(fetch_rdata_i) begin
        case (instr_b)
            imm_b_type[31] = imm_b_type[30]; // Sign extension
        endcase
    end

    // Predict jumps as always taken
    always @(fetch_valid_i) begin
        predict_branch_taken_o = |instr_j;
        predict_branch_pc_o = fetch_pc_i + imm_j_type_se;
    end

endmodule

input.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction outputs
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,
  output logic [7:0] predict_confidence_o,
  output logic        predict_exception_o,
  output logic [3:0] predict_branch_type_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic instr;
  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20] + reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(instr_b)
      instr_b : begin
        if (imm_b_type[31] == 1'b1)
          predict_branch_taken_o = 1'b1;
        else
          predict_branch_taken_o = 1'b0;
      endcase
      predict_branch_pc_o = fetch_pc_i + branch_imm; 
      predict_confidence_o = 8'd90;
      predict_exception_o = 1'b0;
      predict_branch_type_o = 3'b011;
    endcase
    case(instr_jal)
      instr_jal : begin
        predict_branch_taken_o = 1'b1;
        predict_branch_pc_o = fetch_pc_i + imm_jal_type;
        predict_confidence_o = 8'd100;
        predict_exception_o = 1'b0;
        predict_branch_type_o = 3'b001;
      endcase
    case(instr_jalr)
      instr_jalr : begin
        predict_branch_taken_o = 1'b1;
        predict_branch_pc_o = fetch_pc_i + imm_jalr_type;
        predict_confidence_o = 8'd100;
        predict_exception_o = 1'b0;
        predict_branch_type_o = 3'b010;
      endcase
    case(instr_cj)
      instr_cj : begin
        if (imm_cb_type[31] == 1'b1)
          predict_branch_taken_o = 1'b1;
          predict_confidence_o = 8'd90;
        else
          predict_branch_taken_o = 1'b0;
          predict_confidence_o = 8'd50;
        endcase
        predict_branch_pc_o = fetch_pc_i + imm_cb_type;
        predict_exception_o = 1'b0;
        predict_branch_type_o = 3'b100;
      endcase
    case(instr_cb)
      instr_cb : begin
        predict_branch_taken_o = 1'b1;
        predict_pc_o = fetch_pc_i + imm_cb_type;
        predict_confidence_o = 8'd50;
        predict_exception_o = 1'b0;
        predict_branch_type_o = 3'b101;
      endcase
    default    : begin
      predict_branch_taken_o = 1'b0;
      predict_pc_o = fetch_pc_i;
      predict_confidence_o = 8'd0;
      predict_exception_o = 1'b1;
      predict_branch_type_o = 4'b000;
    endcase
  end
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);

endmodule

always @(*) begin
  // Instruction Decoding
  instr = fetch_rdata_i;
  instr_jal = (instr[6:0] == 7'h6F);
  instr_jalr = (instr[6:0] == 7'h67);
  instr_b = (instr[6:0] == 7'h63);
  instr_cj = (instr[6:0] == 7'h6C);
  instr_cb = (instr[6:0] == 7'h6B);

  // Branch Immediate Selection
  if (instr_jal) begin
    imm_jal_type = instr[24:20] << 16; // Sign-extended 20-bit immediate
    branch_imm = imm_jal_type;
  end
  else if (instr_jalr) begin
    imm_jalr_type = instr[23:12] + reg_addr; // Add register address to 12-bit immediate
    branch_imm = imm_jalr_type;
  end
  else if (instr_b) begin
    imm_b_type = {instr[29:30], instr[28:0]'b0, instr[27:25]'b0, instr[26:23]'b0, instr[22:16]'b0, instr[15:14]'b0}; // Sign-extend the immediate
    branch_imm = imm_b_type;
  end
  else if (instr_cj) begin
    imm_cj_type = instr[29:24]'b0; // Extract the immediate value for CJ
    branch_imm = imm_cj_type;
  end
  else if (instr_cb) begin
    imm_cb_type = instr[29:24]'b0; // Extract the immediate value for CB
    branch_imm = imm_cb_type;
  end
  else begin
    branch_imm = imm_b_type + 0;
  end

  // Branch Taken Decision
  instr_b_taken = (branch_imm[31] == 1); // Check if the immediate sign bit is set

  // Branch Prediction
  predict_branch_taken_o = (instr_jal || instr_jalr || instr_b || instr_cj || instr_cb) || instr_b_taken;

  // Branch Target Address Calculation
  predict_branch_pc_o = fetch_pc_i + branch_imm;
end

// Branch prediction and branch target calculation
always_comb begin
  // Instruction decoding
  instr = fetch_rdata_i;
  reg_addr = register_addr_i;

  // JAL instruction
  instr_jal = (instr[6:0] == 7'h6F);
  if (instr_jal) begin
    imm_jal_type = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
    predict_branch_type_o = 2'b00; // JAL
  end

  // JALR instruction
  instr_jalr = (instr[6:0] == 7'h67);
  if (instr_jalr) begin
    imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + reg_addr;
    predict_branch_type_o = 2'b01; // JALR
  end

  // B-type instruction
  instr_b = (instr[6:0] == 7'h63);
  if (instr_b) begin
    imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
    predict_branch_type_o = 2'b10; // B-type
    instr_b_taken = (imm_b_type[31] == 1'b1);
  end

  // CJ and CB instruction
  instr_cj = (instr[31] == instr[12]);
  instr_cb = (instr[11] == instr[6]);
  if (instr_cj) begin
    imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0 };
    predict_branch_type_o = 2'b11; // CJ/CB
    instr_b_taken = (imm_cj_type[31] == 1'b1);
  end

  // Branch prediction logic
  if (fetch_valid_i) begin
    if (instr_jal || instr_jalr || instr_b_taken || instr_cj || instr_cb) begin
      predict_branch_taken_o = 1'b1;
      predict_confidence_o = 100;
    end else begin
      predict_branch_taken_o = 1'b0;
      predict_confidence_o = (instr_b_taken ? 90 : 50);
    end
  end else begin
    predict_branch_taken_o = 1'b0;
    predict_confidence_o = 0;
    predict_exception_o = 1'b1;
  end

  // Branch target address calculation
  if (predict_branch_taken_o) begin
    predict_branch_pc_o = fetch_pc_i + imm_jal_type + imm_jalr_type + imm_b_type + imm_cj_type;
  end else begin
    predict_branch_pc_o = fetch_pc_i;
  end
end

output.rtl/strobe_divider.sv:
module strobe_divider #(
    parameter MaxRatio_g = 10, // Maximum division ratio (positive integer)
    parameter Latency_g  = 1   // Latency: 0 or 1
)(
    input  wire                              Clk,        // Clock input
    input  wire                              Rst,        // Synchronous reset (active high)
    input  wire [log2ceil(MaxRatio_g)-1:0]   In_Ratio,   // Division ratio input
    input  wire                              In_Valid,   // Input pulse valid
    output reg                               Out_Valid,  // Output pulse valid
    input  wire                              Out_Ready   // Output ready signal
);

    function integer log2ceil;
        input integer value;
        integer i;
        begin
            log2ceil = 1;
            for (i = 0; (2 ** i) < value; i = i + 1)
                log2ceil = i + 1;
        end
    endfunction

    // Internal state registers
    reg [log2ceil(MaxRatio_g)-1:0] r_Count, r_next_Count; // Counter register
    reg                            r_OutValid, r_next_OutValid; // Registered OutValid signal
    reg                            OutValid_v; // Intermediate OutValid for latency

    // Combinational Logic
    always @* begin
        // Latency handling
        if (Latency_g == 0) begin
            OutValid_v = r_OutValid;
        end else begin
            OutValid_v = r_next_OutValid;
        end

        // Counter logic for division ratio
        if (In_Ratio == 0) begin
            if (In_Valid) begin
                r_Count <= r_Count + 1;
                r_OutValid <= 1;
            end
        end else begin
            if (In_Valid) begin
                r_Count <= r_Count + 1;
            end
            if (r_Count == In_Ratio) begin
                r_OutValid <= 1;
                r_Count <= 0;
            end
        end

        // Output ready handshake
        if (Out_Ready) begin
            r_OutValid <= 0;
        end
    end

    // Sequential Logic
    always @(posedge Clk) begin
        if (Rst) begin
            r_Count <= 0;
            r_OutValid <= 0;
        end else begin
            // Update next state for counters
            r_next_Count <= r_Count;
            r_next_OutValid <= r_OutValid;

            // Update output validity
            if (Out_Ready) begin
                r_OutValid <= 0;
            end else begin
                r_OutValid <= OutValid_v;
            end
        end
    end

endmodule

input.rtl/swizzler.sv:
module swizzler #(
    // Parameter N: Number of serial data lanes (default is 8)
    parameter int N = 8
)(
    input clk,
    input reset,
    // Serial Input data lanes
    input  logic [N-1:0]                 data_in,
    // Encoded mapping input: concatenation of N mapping indices, each M bits wide
    input  logic [N*$clog2(N)-1:0]       mapping_in,
    // Control signal: 0 - mapping is LSB to MSB, 1 - mapping is MSB to LSB
    input  logic                         config_in,
    // Serial Output data lanes
    output logic [N-1:0]                 data_out
);
    localparam int M = $clog2(N);
    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin : lane_mapping
            assign map_idx[j] = mapping_in[j*M +: M];
        end
    endgenerate

    always_ff @ (posedge clk) begin
        if (reset) begin
            data_out <= '0;
        end
        else begin
            for (int i = 0; i < N; i++) begin
                if (map_idx[i] >= 0 && map_idx[i] < N) begin
                    if (config_in) begin
                        data_out[i] <= data_in[map_idx[i]];
                    end
                    else begin
                        data_out[N-1-i] <= data_in[map_idx[i]];
                    end
                end
                else begin
                    data_out[i] <= '0;
                end
            end
        end
    end
endmodule

