input.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo #(parameter DATA_WIDTH = 8, parameter ADDR_WIDTH = 3) (
    input clk,
    input reset,
    input write_en,
    input [DATA_WIDTH-1:0] data_in,
    output reg empty,
    output reg full,
    output [DATA_WIDTH-1:0] data_out
);

    // Define the memory array with configurable depth
    logic [DATA_WIDTH-1:0] mem [((1<<ADDR_WIDTH)-1:0)];
    logic [ADDR_WIDTH-1:0] head, tail;

    // Initialize the memory and pointers
    initial begin
        empty = 1'b1;
        full = 1'b0;
        head = 0;
        tail = (1<<ADDR_WIDTH)-1;
        mem = {{(1 << DATA_WIDTH)-1{1'b0}}}; // Fill with zeros
    end

    // Process on rising edge of the clock
    always_ff @(posedge clk) begin
        if (reset) begin
            empty <= 1'b1;
            full <= 1'b0;
            mem = {{(1 << DATA_WIDTH)-1{1'b0}}};
            head = 0;
            tail = (1<<ADDR_WIDTH)-1;
        end else begin
            if (write_en && !full) begin
                mem[tail] = data_in;
                tail = (tail + 1) & ((1<<ADDR_WIDTH)-1);
                full <= 1'b0;
            end

            if (read_en && !empty) begin
                data_out <= mem[head];
                head = (head + 1) & ((1<<ADDR_WIDTH)-1);
                empty <= 1'b0;
            end
        end
    end

endmodule

output.rtl/sync_serial_communication_top.sv:
module sync_serial_communication_top (
    input clk,
    input reset_n,
    input [63:0] data_in,
    input [2:0] sel,
    output reg serial_out,
    output reg done,
    output reg serial_clk
);

    wire [63:0] data_out;
    wire [1:0] sel_sel;

    tx_block tx_inst(.clk(clk), .reset_n(reset_n), .data_in(data_in), .sel(sel_sel), .serial_out(serial_out), .serial_clk(serial_clk));
    rx_block rx_inst(.clk(clk), .reset_n(reset_n), .data_in(serial_out), .sel(sel_sel), .serial_clk(serial_clk), .data_out(data_out), .done(done));

    always @ (posedge clk) begin
        if (reset_n) begin
            serial_out <= 1'b0;
            done <= 1'b0;
            serial_clk <= 1'b0;
        end else begin
            sel_sel = {sel[2:0], sel};
            case (sel_sel)
                3'b0: begin
                    serial_out <= 1'b0;
                    done <= 1'b0;
                    serial_clk <= 1'b0;
                end
                3'b1: begin
                    serial_out <= data_in[7:0];
                    done <= 1'b0;
                    serial_clk <= 1'b0;
                end
                3'b2: begin
                    serial_out <= data_in[15:0];
                    done <= 1'b0;
                    serial_clk <= 1'b0;
                end
                3'b3: begin
                    serial_out <= data_in[31:0];
                    done <= 1'b0;
                    serial_clk <= 1'b0;
                end
                3'b4: begin
                    serial_out <= data_in;
                    done <= 1'b0;
                    serial_clk <= 1'b0;
                end
                default: begin
                    serial_out <= 1'b0;
                    done <= 1'b0;
                    serial_clk <= 1'b0;
                end
            endcase
        end
    end

endmodule

output.rtl/thermostat.v:
module thermostat(
    input wire [5:0] i_temp_feedback,
    input wire i_fan_on,
    input wire i_enable,
    input wire i_fault,
    input wire i_clr,
    input wire i_clk,
    input wire i_rst,
    output reg [1:0] o_state,
    output reg o_heater_full,
    output reg o_heater_medium,
    output reg o_heater_low,
    output reg o_aircon_full,
    output reg o_aircon_medium,
    output reg o_aircon_low,
    output reg o_fan
);

    // Reset and enable logic
    always @(posedge i_clk or posedge i_rst) begin
        if (i_rst)
            o_state <= 3'b000;
        else if (i_enable == 0)
            o_heater_full <= 0;
            o_heater_medium <= 0;
            o_heater_low <= 0;
            o_aircon_full <= 0;
            o_aircon_medium <= 0;
            o_aircon_low <= 0;
            o_fan <= 0;
        else
            // State transition logic
            case(o_state)
                3'b000: o_state <= i_full_cold ? 3'b100 : o_state;
                3'b001: o_state <= i_medium_cold ? 3'b100 : o_state;
                3'b010: o_state <= i_low_cold ? 3'b100 : o_state;
                3'b011: o_state <= 3'b000;
                3'b100: o_state <= i_full_hot ? 3'b010 : o_state;
                3'b101: o_state <= i_medium_hot ? 3'b010 : o_state;
                3'b110: o_state <= i_low_hot ? 3'b010 : o_state;
                default: o_state <= 3'b000;
            endcase
    end

    // Fault and clr logic
    always @(posedge i_clk or posedge i_rst) begin
        if (i_fault)
            o_heater_full <= 0;
            o_heater_medium <= 0;
            o_heater_low <= 0;
            o_aircon_full <= 0;
            o_aircon_medium <= 0;
            o_aircon_low <= 0;
            o_fan <= 0;
        else if (i_clr)
            o_state <= 3'b000;
        else
            // Normal output logic
            case(o_state)
                3'b000: o_heater_full <= 1; o_heater_medium <= 0; o_heater_low <= 0;
                3'b001: o_heater_full <= 0; o_heater_medium <= 1; o_heater_low <= 0;
                3'b010: o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 1;
                3'b100: o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
                3'b101: o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
                3'b110: o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
                default: o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
            endcase
    end

    // Fan logic
    always @(posedge i_clk or posedge i_rst) begin
        if (i_fan_on)
            o_fan <= 1;
        else
            o_fan <= 0;
    end

endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite #(
    parameter DATA_WIDTH = 32,
    parameter ADDR_WIDTH = 4
) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] axi_addr,
    input [DATA_WIDTH-1:0] axi_wdata,
    input axi_write_en,
    input axi_read_en,
    output [DATA_WIDTH-1:0] axi_rdata,
    output interrupt
);

    // Registers
    reg [DATA_WIDTH-1:0] count;
    reg [DATA_WIDTH-1:0] match_value;
    reg [DATA_WIDTH-1:0] reload_value;
    reg enable, interval_mode, interrupt_enable;
    reg match_flag;
    reg [DATA_WIDTH-1:0] status;

    // State machine
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 0;
            match_value <= 0;
            reload_value <= 0;
            enable <= 0;
            interval_mode <= 0;
            interrupt_enable <= 0;
            match_flag <= 0;
            status <= 0;
        end else begin
            enable <= control_register[3:0];
            interval_mode <= control_register[7];
            interrupt_enable <= control_register[8];
            match_flag <= (count == match_value) & interval_mode;
            status <= interrupt_enable ? 1'b1 : 1'b0;
        end
    end

    // Counter logic
    always @(posedge clk) begin
        if (enable) begin
            if (interval_mode) begin
                if (match_flag) begin
                    count <= reload_value;
                    interrupt <= 1;
                    match_flag <= 0;
                end else begin
                    count <= count + 1;
                end
            end else begin
                count <= count + 1;
            end
        end else begin
            count <= 0;
        end
    end

    // AXI-Lite Interface
    assign axi_rdata = (axi_read_en) ? count : 1'bz;
    assign axi_write_en = (axi_addr == control_register_address) ? enable : 1'b0;

    // Control Register
    reg [ADDR_WIDTH-1:0] control_register;
    assign control_register = (axi_addr == 0) ? control_register : 1'bz;

    // Status Register
    reg [ADDR_WIDTH-1:0] status_register;
    assign status_register = (axi_addr == status_register_address) ? status : 1'bz;

    // Interrupt Handling
    always @(posedge clk) begin
        if (status_register[0]) begin
            interrupt <= 1;
            status <= 0;
        end else begin
            interrupt <= 1'b0;
        end
    end

endmodule

output.rtl/vending_machine.sv:
module vending_machine (
    input clk,
    input rst,
    input item_button,
    input [2:0] item_selected,
    input [3:0] coin_input,
    input cancel,
    output reg dispense_item,
    output reg return_change,
    output reg [4:0] item_price,
    output reg [4:0] change_amount,
    output reg [2:0] dispense_item_id,
    output reg error,
    output reg return_money
);

    // State declaration
    typedef enum logic [1:0] {IDLE, ITEM_SELECTION, PAYMENT_VALIDATION, DISPENSING_ITEM, RETURN_CHANGE, RETURN_MONEY} state_t;
    reg [1:0] current_state, next_state;

    // State transition logic
    always @(posedge clk or posedge rst) begin
        if (rst)
            current_state <= IDLE;
        else
            current_state <= next_state;
    end

    // State transition logic
    always @* begin
        case (current_state)
            IDLE:
                if (item_button) begin
                    next_state = ITEM_SELECTION;
                end
                else begin
                    next_state = IDLE;
                end

            ITEM_SELECTION:
                if (item_selected >= 3'b001 && item_selected <= 3'b100) begin
                    next_state = PAYMENT_VALIDATION;
                end
                else begin
                    error <= 1'b1;
                    next_state = RETURN_MONEY;
                end

            PAYMENT_VALIDATION:
                if (cancel) begin
                    error <= 1'b1;
                    next_state = RETURN_MONEY;
                end
                else begin
                    // Accumulate coins
                    if (coin_input == 4'b0000 || coin_input == 4'b0001 || coin_input == 4'b0010 || coin_input == 4'b0100) begin
                        // Assuming we have a register to accumulate coins
                        // coins_accumulated <= coins_accumulated + coin_input;

                        if (coins_accumulated >= item_price) begin
                            next_state = DISPENSING_ITEM;
                        end
                        else begin
                            error <= 1'b1;
                            next_state = RETURN_MONEY;
                        end
                    end
                    else begin
                        error <= 1'b1;
                        next_state = RETURN_MONEY;
                    end
                end

            DISPENSING_ITEM:
                if (coins_accumulated > item_price) begin
                    dispense_item <= 1'b1;
                    next_state = RETURN_CHANGE;
                end
                else begin
                    next_state = IDLE;
                end

            RETURN_CHANGE:
                if (coins_accumulated > change_amount) begin
                    change_amount <= coins_accumulated - change_amount;
                    next_state = IDLE;
                    return_change <= 1'b1;
                end
                else begin
                    next_state = IDLE;
                end

            RETURN_MONEY:
                if (coins_accumulated > 0) begin
                    return_money <= 1'b1;
                    next_state = IDLE;
                end
                else begin
                    next_state = IDLE;
                end

            default:
                next_state = IDLE;
        end
    end

    // Output logic
    always @(posedge clk) begin
        if (error)
            dispense_item <= 1'b0;
        else
            dispense_item <= 1'b0;

        if (return_money)
            return_change <= 1'b0;
        else
            return_change <= 1'b0;

        item_price = item_price; // Assuming item_price is set in ITEM_SELECTION state
        change_amount = change_amount; // Assuming change_amount is calculated in RETURN_CHANGE state
        dispense_item_id = dispense_item_id; // Assuming dispense_item_id is set in DISPENSING_ITEM state
        error = error;
    end

endmodule

output.rtl/vga_controller.sv:
module vga_controller(
    input clk,
    input reset,
    input [7:0] color_in,
    output reg hsync,
    output reg vsync,
    output reg [7:0] red,
    output reg [7:0] green,
    output reg [7:0] blue,
    output reg [9:0] next_x,
    output reg [9:0] next_y,
    output reg sync,
    output reg clk,
    output reg blank
);

    // State and counter declarations
    typedef enum logic [1:0] {
        H_ACTIVE,
        H_FRONT,
        H_PULSE,
        H_BACK
    } h_state_t;

    logic [9:0] h_counter;
    logic [9:0] v_counter;

    // State machine and timing parameters
    logic [2:0] h_state, v_state;
    localparam H_ACTIVE_TIME = 640;
    localparam H_FRONT_TIME = 16;
    localparam H_PULSE_TIME = 96;
    localparam H_BACK_TIME = 48;
    localparam V_ACTIVE_LINES = 480;
    localparam V_FRONT_LINES = 10;
    localparam V_PULSE_LINES = 2;
    localparam V_BACK_LINES = 33;

    // State transition logic
    always_ff @(posedge clk) begin
        case (h_state)
            H_ACTIVE: begin
                if (reset) begin
                    h_counter <= 0;
                    h_state <= H_ACTIVE;
                    line_done <= 0;
                end else begin
                    h_counter <= h_counter + 1;
                    if (h_counter >= H_ACTIVE_TIME) begin
                        h_state <= H_FRONT;
                    end
                end
            end
            H_FRONT: begin
                if (h_counter >= H_FRONT_TIME) begin
                    h_state <= H_PULSE;
                end
            end
            H_PULSE: begin
                if (h_counter >= H_PULSE_TIME) begin
                    h_state <= H_BACK;
                end
            end
            H_BACK: begin
                if (h_counter >= H_BACK_TIME) begin
                    h_state <= H_ACTIVE;
                    line_done <= 1;
                end
            end
        endcase

        case (v_state)
            V_ACTIVE: begin
                if (reset) begin
                    v_counter <= 0;
                    v_state <= V_ACTIVE;
                end else begin
                    v_counter <= v_counter + 1;
                    if (v_counter >= V_ACTIVE_LINES) begin
                        v_state <= V_FRONT;
                    end
                end
            end
            V_FRONT: begin
                if (v_counter >= V_FRONT_LINES) begin
                    v_state <= V_PULSE;
                end
            end
            V_PULSE: begin
                if (v_counter >= V_PULSE_LINES) begin
                    v_state <= V_BACK;
                end
            end
            V_BACK: begin
                if (v_counter >= V_BACK_LINES) begin
                    v_state <= V_ACTIVE;
                end
            end
        endcase
    end

    // Color output logic
    always_ff @(posedge clk) begin
        if (h_state == H_ACTIVE) begin
            red <= color_in[7:5];
            green <= color_in[4:2];
            blue <= color_in[1:0];
        end else begin
            red <= 8'b0;
            green <= 8'b0;
            blue <= 8'b0;
        end

        if (v_state == V_ACTIVE) begin
            next_x <= h_counter;
            next_y <= v_counter;
        end else {
            next_x <= 0;
            next_y <= 0;
        }
    end

    // Sync and blanking logic
    always_ff @(posedge clk) begin
        sync <= 1'b0; // Fixed to LOW as per design
        blank <= hsync | vsync;
    end

endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic H_ACTIVE_STATE  = 8'd0;
    parameter logic H_FRONT_STATE   = 8'd1;
    parameter logic H_PULSE_STATE   = 8'd2;
    parameter logic H_BACK_STATE    = 8'd3;
    parameter logic V_ACTIVE_STATE  = 8'd0;
    parameter logic V_FRONT_STATE   = 8'd1;
    parameter logic V_PULSE_STATE   = 8'd2;
    parameter logic V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    h_counter <= h_counter + 1'b1;
                    if (h_counter == H_ACTIVE - 1'b1) begin
                        h_state <= H_FRONT_STATE;
                    end
                end
                H_FRONT_STATE: begin
                    h_counter <= h_counter + 1'b1;
                    if (h_counter == H_FRONT - 1'b1) begin
                        h_state <= H_PULSE_STATE;
                    end
                end
                H_PULSE_STATE: begin
                    h_counter <= h_counter + 1'b1;
                    if (h_counter == H_PULSE - 1'b1) begin
                        h_state <= H_BACK_STATE;
                        line_done <= HIGH;
                    end
                end
                H_BACK_STATE: begin
                    h_counter <= h_counter + 1'b1;
                    if (h_counter == H_BACK - 1'b1) begin
                        h_state <= H_ACTIVE_STATE;
                    end
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    v_counter <= v_counter + 1'b1;
                    if (v_counter == V_ACTIVE - 1'b1) begin
                        v_state <= V_FRONT_STATE;
                    end
                end
                V_FRONT_STATE: begin
                    v_counter <= v_counter + 1'b1;
                    if (v_counter == V_FRONT - 1'b1) begin
                        v_state <= V_PULSE_STATE;
                    end
                end
                V_PULSE_STATE: begin
                    v_counter <= v_counter + 1'b1;
                    if (v_counter == V_PULSE - 1'b1) begin
                        v_state <= V_BACK_STATE;
                    end
                end
                V_BACK_STATE: begin
                    v_counter <= v_counter + 1'b1;
                    if (v_counter == V_BACK - 1'b1) begin
                        v_state <= V_ACTIVE_STATE;
                    end
                end
            endcase

            // Handle RGB signals
            always @(h_state or v_state) begin
                case (h_state)
                    H_ACTIVE_STATE: begin
                        red <= color_in;
                        green <= color_in;
                        blue <= color_in;
                    end
                    H_FRONT_STATE: begin
                        red <= HIGH;
                        green <= HIGH;
                        blue <= HIGH;
                    end
                    H_PULSE_STATE: begin
                        red <= LOW;
                        green <= LOW;
                        blue <= LOW;
                    end
                    H_BACK_STATE: begin
                        red <= LOW;
                        green <= LOW;
                        blue <= LOW;
                    end
                endcase

                case (v_state)
                    V_ACTIVE_STATE: begin
                        red <= color_in;
                        green <= color_in;
                        blue <= color_in;
                    end
                    V_FRONT_STATE: begin
                        red <= HIGH;
                        green <= HIGH;
                        blue <= HIGH;
                    end
                    V_PULSE_STATE: begin
                        red <= LOW;
                        green <= LOW;
                        blue <= LOW;
                    end
                    V_BACK_STATE: begin
                        red <= LOW;
                        green <= LOW;
                        blue <= LOW;
                    end
                endcase
            end
        end
    end

    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync_reg & vsync_reg;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

